    public async Task SetTemplatePortfolioBulkAsync(IList<TemplatePortfolio> items, Guid templateId, CancellationToken cancellationToken)
    {
      await RepoCallAsync(
        nameof(ModelingRepository.CreateItemsBulkAsync) + ":" + typeof(TemplatePortfolio),
        action: async (context) =>
        {
          var dbSet = await context.TemplatePortfolios.Where(te => te.TemplateId == templateId).AsNoTracking().ToListAsync().ConfigureAwait(false);
          var itemsToRemove = dbSet.Where(d => !items.Any(i => i.PortfolioId == d.PortfolioId)).ToList();
          var itemsToAdd = items.Where(i => !dbSet.Any(d => d.PortfolioId == i.PortfolioId)).ToList();

          //delete our items
          context.RemoveRange(itemsToRemove);
          // Adding the item to the context will generate a Guid for the ID.
          await context.AddRangeAsync(itemsToAdd, cancellationToken).ConfigureAwait(false);

          //set our CreatedBy, CreateAt, etc
          context.SetIdentityFields(_stateManager, true);

          // Save the Fields in the database.
          await context.SaveChangesAsync(cancellationToken).ConfigureAwait(false);
        },
        cancellationToken: cancellationToken
      ).ConfigureAwait(false);

      return;
    }

