    #region Cached Data

    private async Task EnsureDomainDataSeedingIsCompletedAsync(string ownerId, CancellationToken cancellationToken)
    {
      if (_domainDataSeedingCompleted)
        return;

      var domainDataClient = await ServiceProvider.GetGrpcClientAsync<SolvasAm.DomainData.GrpcApi.V1.DomainDataService.DomainDataServiceClient>("solvasam-domaindata", cancellationToken).ConfigureAwait(false);
      var seedRecordName = SolvasAm.Common.GrpcApi.ResourceNames.ResourceName.Format<SolvasAm.Common.GrpcApi.V1.DataSeedRecord>(ownerId, "initial-seed");

      await Backoff.RunAsync(
        action: async (ct) =>
        {
          var dataSeedRecord = await domainDataClient.GetDataSeedRecordAsync(new SolvasAm.Common.GrpcApi.V1.GetRequest { Name = seedRecordName }, cancellationToken: ct);
          _domainDataSeedingCompleted = true;
        },
        errorHandler: (exception, nextDuration, _) =>
        {
          Logger.Error("Initial seeding is not yet complete: {exception}.\nRetrying in {nextDuration}.", exception, nextDuration);
          return Task.FromResult(true);
        },
        cancellationToken: cancellationToken
        ).ConfigureAwait(false);
    }

    private Task EnsureObjectLookupIsPopulated<T>(string ownerId, IObjectLookup<T> genericLookup, CancellationToken cancellationToken) => Backoff.RunAsync(
        action: (_) =>
        {
          // With the second param set to true, this should throw a GenericMapException if the cache for this ownerId is empty.
          genericLookup.BeginScope(ownerId, true);
          return Task.CompletedTask;
        },
        errorHandler: (exception, nextDuration, _) =>
        {
          if (exception is GenericMapException)
          {
            Logger.Error(exception, "Cache is not yet populated. \nRetrying in {nextDuration}.", nextDuration);
            return Task.FromResult(true);
          }
          //any other exception, exit the backoff and propogate the exception up the call stack.
          return Task.FromResult(false);
        },
        cancellationToken: cancellationToken
        );

    private Task EnsureObjectMapIsPopulated<T>(string ownerId, IObjectMap<T> genericMap, CancellationToken cancellationToken) => Backoff.RunAsync(
        action: (_) =>
        {
          // With the second param set to true, this should throw a GenericMapException if the cache for this ownerId is empty.
          genericMap.BeginScope(ownerId, true);
          return Task.CompletedTask;
        },
        errorHandler: (exception, nextDuration, _) =>
        {
          if (exception is GenericMapException)
          {
            Logger.Error(exception, "Cache is not yet populated.\nRetrying in {nextDuration}.", nextDuration);
            return Task.FromResult(true);
          }
          //any other exception, exit the backoff and propogate the exception up the call stack.
          return Task.FromResult(false);
        },
        cancellationToken: cancellationToken
        );

    private async Task RefreshDataDictionaryCache(string ownerId, CancellationToken cancellationToken)
    {
      using (_dataDictFieldCache.BeginScope(ownerId, true))
      {
        await _dataDictFieldCache.BuildAsync(cancellationToken).ConfigureAwait(false);
      }
    }

    #region LookupItem

    public async Task<IList<string>> GetLookupCodes(string ownerId, string lookupType, CancellationToken cancellationToken)
    {
      // This method will await until domain data seeding is completed 
      await EnsureDomainDataSeedingIsCompletedAsync(ownerId, cancellationToken).ConfigureAwait(false);
      // This method will await until the lookup items cache is populated
      await EnsureObjectLookupIsPopulated(ownerId, _referenceDataCache, cancellationToken).ConfigureAwait(false);
      using (_referenceDataCache.BeginScope(ownerId, true))
      {
        var lookupItems = await _referenceDataCache.GetOrAddAsync(lookupType, cancellationToken).ConfigureAwait(false);
        return lookupItems.Select(l => l.Code).ToList();
      }
    }

    public async Task<IList<LookupItem>> GetLookupItems(string ownerId, string lookupType, CancellationToken cancellationToken)
    {
      // This method will await until domain data seeding is completed 
      await EnsureDomainDataSeedingIsCompletedAsync(ownerId, cancellationToken).ConfigureAwait(false);
      // This method will await until the lookup items cache is populated
      await EnsureObjectLookupIsPopulated(ownerId, _referenceDataCache, cancellationToken).ConfigureAwait(false);
      using (_referenceDataCache.BeginScope(ownerId, true))
      {
        var lookupItems = await _referenceDataCache.GetOrAddAsync(lookupType, cancellationToken).ConfigureAwait(false);
        return lookupItems.ToList();
      }
    }

    public async Task<IList<LookupItem>> GetLookupItems(string ownerId, IList<string> lookupTypes, CancellationToken cancellationToken)
    {
      // This method will await until domain data seeding is completed 
      await EnsureDomainDataSeedingIsCompletedAsync(ownerId, cancellationToken).ConfigureAwait(false);
      // This method will await until the lookup items cache is populated
      await EnsureObjectLookupIsPopulated(ownerId, _referenceDataCache, cancellationToken).ConfigureAwait(false);
      using (_referenceDataCache.BeginScope(ownerId, true))
      {
        var getTasks = lookupTypes.Select(lookupType => _referenceDataCache.GetOrAddAsync(lookupType, cancellationToken)).ToList();
        var lookupItems = await Task.WhenAll(getTasks).ConfigureAwait(false);
        return lookupItems.Where(i => i != null).SelectMany(item => item).ToList();
      }
    }

