    public async Task<IList<object>> CompareComplianceModelsAsync(string ownerId, string modelId1, string modelId2, int? skip, int? take, string orderExpression, CancellationToken cancellationToken)
    {
      var models = new List<object>();

      var builder = _sprocContext.CustomSprocCommand<Core.Model.ComplianceModel.Model>(ownerId, ModelingSprocContext.PS_MODEL_COMPARE)
       .WithParameters(
          new SprocParameter("m_id_1", modelId1),
          new SprocParameter("m_id_2", modelId2)
       )
       .WithResultSetAction((_, record) =>
       {
         var model = new
         {
           ElementType = record.GetValue<string>("element_type"),
           FirstModelElementId = record.GetValue<string>("element_id_1"),
           FirstModelElementDescription = record.GetValue<string>("model_1_description"),
           SecondModelElementId = record.GetValue<string>("element_id_2"),
           SecondModelElementDescription = record.GetValue<string>("model_2_description"),
           Differences = record.GetValue<string>("differences"),
           ElementTypeDescription = record.GetValue<string>("element_type_desc"),
         };
         models.Add(model);
       });

      if (skip.HasValue)
        builder = builder.Skip(skip.Value);
      if (take.HasValue)
        builder = builder.Take(take.Value);

      if (!string.IsNullOrEmpty(orderExpression))
      {
        builder = builder.OrderBy(orderExpression);
      }
      // In this custom method, we are executing the sproc and customizing the result set which is a list of objects using the WithResultSetAsyncAction custom action.
      await builder.ExecuteAsync(cancellationToken).ConfigureAwait(false);

      return models;
    }

    public async Task<Google.Protobuf.WellKnownTypes.Struct> ExportComplianceModelAsync(string ownerId, string portfolioId, string modelId, CancellationToken cancellationToken)
    {
      var jsonResult = new StringBuilder();
      string jsonColumnName = null;
      var _ = await _sprocContext.GlobalSprocCommand(ownerId, ModelingSprocContext.PS_MODEL_EXPORT_JSON)
        .WithParameters(
          new SprocParameter("entity_id", portfolioId),
          new SprocParameter("m_id", modelId)
        )
        .WithResultSetAction((record) =>
        {
          jsonColumnName ??= record.ColumnNames.First();
          jsonResult.Append(record.GetValue<string>(jsonColumnName));
        })
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);

      if (jsonResult.Length == 0)
      {
        jsonResult.Append("[]");
      }
      return JsonParser.Default.Parse<Google.Protobuf.WellKnownTypes.Struct>(jsonResult.ToString());


    }

