    #region HypotheticalFieldChange.Rule

    public async Task<IList<Core.Model.HypotheticalFieldChange.Rule>> GetHypotheticalFieldChangeRulesAsync(string ownerId, string filter, CancellationToken cancellationToken)
    {
      var valuePairs = _sprocTranslator.ParseForValuePairs<Core.Model.HypotheticalFieldChange.Rule>(filter);

      bool.TryParse(valuePairs.GetValueOrDefault("exclude_expressions")?.Item2 ?? "false", out bool excludeExpressions);
      var expressionIdMap = new Dictionary<long, string>();

      var (rules, _) = await _sprocContext.GetSprocCommand<Core.Model.HypotheticalFieldChange.Rule>(ownerId)
        .WithParameters(
          new SprocParameter("dcb_id", valuePairs.GetValueOrDefault("id")?.Item2),
          new SprocParameter("dcb_code", valuePairs.GetValueOrDefault("code")?.Item2),
          new SprocParameter("dcg_id", valuePairs.GetValueOrDefault("scenario_id")?.Item2),
          new SprocParameter("entity_id", valuePairs.GetValueOrDefault("portfolio_id")?.Item2)
        )
        .WithResultSetAsyncAction(async (rule, record) =>
        {
          Field targetField = null;
          var targetFieldStr = record.GetValue<string>("target_field");
          if (!string.IsNullOrEmpty(targetFieldStr))
          {
            using (_dataDictFieldCache.BeginScope(ownerId, true))
            {
              var dictionaryFields = await _dataDictFieldCache.GetByPredicateAsync(f => f.Name == targetFieldStr.Replace("[", "").Replace("]", "") || f.DisplayName == targetFieldStr.Replace("[", "").Replace("]", ""), cancellationToken).ConfigureAwait(false);
              targetField = dictionaryFields.FirstOrDefault();
            }
          }

          if (targetField != null)
          {
            rule.TargetFieldDescription = targetField.DisplayName;
            rule.TargetField = targetField.Name;
          }

          if (!string.IsNullOrEmpty(record.GetValue<string>("value")))
          {
            rule.FormulaExpression = new ModelExpression
            {
              LidClassic = rule.Lid,
              TargetType = "DCBF", //since hypothetical field changes use blocks (in classic) and the applic exp uses DCB for it's expression code, we'll use DCBF here for now.  These codes should be re-visited after moving to the new repos.
              TargetKey = rule.Id,
              TargetKeyClassic = rule.Lid.ToString(),
              Ddx = record.GetValue<string>("value"),
              Label = record.GetValue<string>("value")
            };
          }

          var expId = record.GetValue<string>("applicability_rule");
          expressionIdMap.Add(rule.Lid, expId);
        })
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);

      if (!excludeExpressions)
      {
        var expressionTasksMap = await GetExpressionsAsync(ownerId, expressionIdMap.Select(e => e.Value), cancellationToken).ConfigureAwait(false);

        foreach (var rule in rules)
        {
          if (expressionIdMap.TryGetValue(rule.Lid, out var expId) && !string.IsNullOrEmpty(expId) && expressionTasksMap.TryGetValue(expId, out var modelExpression))
          {
            rule.ApplicabilityExpression = modelExpression;
          }
        }
      }

      return rules;
    }

