    public async Task<Core.Model.HypotheticalFieldChange.Rule> CreateOrUpdateHypotheticalFieldChangeRuleAsync(string ownerId, Core.Model.HypotheticalFieldChange.Rule rule, string portfolioId, int operationConfirmed, CancellationToken cancellationToken)
    {
      var (blockId, _) = await _sprocContext.PutSprocCommand<Core.Model.HypotheticalFieldChange.Rule>(ownerId)
        .WithParameters(
          new SprocParameter("dcb_id", rule.Lid),
          new SprocParameter("dcb_code", rule.Code),
          new SprocParameter("dcg_id", rule.ScenarioIdClassic),
          new SprocParameter("entity_id", portfolioId),
          new SprocParameter("dcb_description", rule.Description),
          new SprocParameter("calc_code", "FIELD_CAL"),
          new SprocParameter("calc_order", rule.Order),
          new SprocParameter("operation_confirmed", 1)
        )
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);

      var block = await GetHypotheticalFieldChangeRuleByIdAsync(ownerId, blockId, cancellationToken).ConfigureAwait(false);

      //target field
      Field targetField = null;
      using (_dataDictFieldCache.BeginScope(ownerId, true))
      {
        if (Guid.TryParse(rule.TargetField, out Guid fieldId))
        {
          targetField = await _dataDictFieldCache.GetOrAddAsync(rule.TargetField, cancellationToken).ConfigureAwait(false);
        }
        else // In unit test we are passing field name so search by predicate here.
        {
          targetField = (await _dataDictFieldCache.GetByPredicateAsync(d => !string.IsNullOrEmpty(rule?.TargetField) && (d.Name == rule.TargetField || d.DisplayName == rule.TargetField.Replace("[", "").Replace("]", "")), cancellationToken).ConfigureAwait(false)).FirstOrDefault();
        }
        if (targetField == null)
        {
          throw new Exception($"{rule.TargetField} not found.");
        }
      }

      await _sprocContext.PutSprocCommand<Core.Model.Calculation.Parameter>(ownerId)
        .WithParameters(
          new SprocParameter("dcb_id", blockId),
          new SprocParameter("dcb_param_id", block.TargetFieldParameterIdClassic),
          new SprocParameter("calc_code", "FIELD_CAL"),
          new SprocParameter("param_code", "TARGET_FIELD"),
          new SprocParameter("param_value", targetField.Name),
          new SprocParameter("param_value_desc", targetField.Description),
          new SprocParameter("param_value_type", "VAL"),
          new SprocParameter("operation_confirmed", operationConfirmed)
        )
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);

      //target value

      if (rule.FormulaExpression != null && (!string.IsNullOrEmpty(rule.FormulaExpression.Ddx) || (block.FormulaExpression != null && !string.IsNullOrEmpty(block.FormulaExpression.Ddx))))
      {

        await _sprocContext.PutSprocCommand<Core.Model.Calculation.Parameter>(ownerId)
        .WithParameters(
          new SprocParameter("dcb_id", blockId),
          new SprocParameter("dcb_param_id", block.FormulaExpressionParameterIdClassic),
          new SprocParameter("calc_code", "FIELD_CAL"),
          new SprocParameter("param_code", "FIELD_VALUE"),
          new SprocParameter("param_value", rule.FormulaExpression.Ddx),
          new SprocParameter("param_value_type", "VAL"),
          new SprocParameter("operation_confirmed", operationConfirmed)
        )
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);
      }

      //applicability expression

      if (rule.ApplicabilityExpression != null && (!string.IsNullOrEmpty(rule.ApplicabilityExpression.Ddx) || (block.ApplicabilityExpression != null && !string.IsNullOrEmpty(block.ApplicabilityExpression.Ddx))))
      {
        await _sprocContext.PutSprocCommand<Core.Model.Calculation.Parameter>(ownerId)
        .WithParameters(
          new SprocParameter("dcb_id", blockId),
          new SprocParameter("dcb_param_id", block.ApplicabilityExpressionParameterIdClassic),
          new SprocParameter("calc_code", "FIELD_CAL"),
          new SprocParameter("param_code", "APPLICABILITY_EXPRESSION"),
          new SprocParameter("param_value", rule.ApplicabilityExpression.Ddx),
          new SprocParameter("param_value_type", "VAL"),
          new SprocParameter("operation_confirmed", operationConfirmed)
        )
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);
      }

      return await GetHypotheticalFieldChangeRuleByIdAsync(ownerId, blockId, cancellationToken).ConfigureAwait(false);

    }

