    public async Task<IList<Core.Model.ImportLayout.Layout>> GetImportLayoutsAsync(string ownerId, string filter, bool populatePortfolio, CancellationToken cancellationToken)
    {
      var valuePairs = _sprocTranslator.ParseForValuePairs<Core.Model.ImportLayout.Layout>(filter);

      var builder = _sprocContext.GetSprocCommand<Core.Model.ImportLayout.Layout>(ownerId)
        .WithParameters(
          new SprocParameter("imp_layout_id", valuePairs.GetValueOrDefault("id")?.Item2),
          new SprocParameter("imp_layout_code", valuePairs.GetValueOrDefault("code")?.Item2),
          new SprocParameter("aggr_level", valuePairs.GetValueOrDefault("aggregation_level")?.Item2),
          new SprocParameter("entity_id", valuePairs.GetValueOrDefault("portfolio_id")?.Item2),
          new SprocParameter("include_all", valuePairs.GetValueOrDefault("include_all")?.Item2 == "1")
        );

      if (populatePortfolio)
      {
        builder = builder.WithResultSetAsyncAction(async (layout, record) =>
        {
          if (layout.PortfoliosClassic?.Count > 0)
          {
            using (_portfolioCache.BeginScope(ownerId, true))
            {
              layout.Portfolios = new List<Guid>();
              foreach (var portfolioId in layout.PortfoliosClassic)
              {
                var portfolios = await _portfolioCache.GetByPredicateAsync(e => e.Lid.ToString() == portfolioId, cancellationToken).ConfigureAwait(false);
                var portfolio = portfolios.FirstOrDefault();
                layout.Portfolios.Add(portfolio.Id);
              }
            }
          }

        });
      }
      var (layouts, _) = await builder.ExecuteAsync(cancellationToken).ConfigureAwait(false);
      return layouts;
    }

