        new SprocParameter("table_name", layout.TableName),
        new SprocParameter("operation_confirmed", operationConfirmed)
      };

      if (portfolioIds?.Count > 0)
      {
        parameters.Add(new SprocParameter("entity_id_string", string.Join(";", portfolioIds)));
