    public async Task<IList<Core.Model.PrincipalBalance.Rule>> GetPBRulesAsync(string ownerId, string filter, CancellationToken cancellationToken)
    {
      var valuePairs = _sprocTranslator.ParseForValuePairs<Core.Model.PrincipalBalance.Rule>(filter);
      bool.TryParse(valuePairs.GetValueOrDefault("exclude_expressions")?.Item2 ?? "false", out bool excludeExpressions);

      var (rules, outParams) = await _sprocContext.GetSprocCommand<Core.Model.PrincipalBalance.Rule>(ownerId)
        .WithParameters(
          new SprocParameter("pbrg_id", valuePairs.GetValueOrDefault("group_id")?.Item2),
          new SprocParameter("pb_rule_id", valuePairs.GetValueOrDefault("id")?.Item2),
          new SprocParameter("pbr_code", valuePairs.GetValueOrDefault("code")?.Item2),
          new SprocParameter("m_id", valuePairs.GetValueOrDefault("model_id")?.Item2),
          new SprocParameter("entity_id", valuePairs.GetValueOrDefault("portfolio_id")?.Item2),
          new SprocParameter("list_by_model", false)
        )
        .WithResultSetAction((rule, record) =>
        {
          rule.IncludeAccruedPikDescription = record.GetValue<bool>("include_accrued_pik") ? "Yes" : "No";
          if (!string.IsNullOrEmpty(record.GetValue<string>("formula_code")) && !excludeExpressions)
          {
            // ModelExpression proto needs the id, code and audit fields which are not available for the formula expression which comes from a string column.
            // These mandatory fields are thus filled in by magic id and code, and the audit fields with the parent object fields.
            rule.FormulaExpression = new ModelExpression
            {
              LidClassic = rule.Lid,
              TargetKey = rule.Id,
              TargetType = "DCBF",
              TargetKeyClassic = rule.Lid.ToString(),
              Ddx = record.GetValue<string>("formula_code"),
              Label = record.GetValue<string>("formula_desc")
            };
          }
        })
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);

      if (!excludeExpressions)
      {
        await PopulateApplicabilityExpressionsAsync(ownerId, rules, cancellationToken).ConfigureAwait(false);
      }

      return rules;
    }

