    public async Task<IList<Core.Model.Calculation.Parameter>> GetCalculationBlockParametersAsync(string ownerId, string filter, Portfolio portfolio, CancellationToken cancellationToken)
    {
      var valuePairs = _sprocTranslator.ParseForValuePairs<Core.Model.Calculation.Parameter>(filter);
      using var routerScope = DatabaseRouter.CreateScope(ownerId);

      Template template = null;

      var (parameters, _) = await _sprocContext.GetSprocCommand<Core.Model.Calculation.Parameter>(ownerId)
        .WithParameters(
          new SprocParameter("dcb_param_id", valuePairs.GetValueOrDefault("id")?.Item2),
          new SprocParameter("dcbp_code", valuePairs.GetValueOrDefault("code")?.Item2),
          new SprocParameter("dcb_id", valuePairs.GetValueOrDefault("block_id")?.Item2),
          new SprocParameter("m_id", valuePairs.GetValueOrDefault("model_id")?.Item2),
          new SprocParameter("entity_id", valuePairs.GetValueOrDefault("portfolio_id")?.Item2)
        )
        .WithResultSetAsyncAction(async (parameter, record) =>
        {
          if (template == null)
          {
            var templateCode = record.GetValue<string>("template_code");
            template = await this.GetByCodeAsync<Template>(templateCode, Guid.Empty, null, cancellationToken).ConfigureAwait(false);
          }
          var templateParameterCode = record.GetValue<string>("template_parameter_code");
          var templateParameter = await this.GetByCodeAsync<TemplateParameter>(templateParameterCode, template.Id, "TemplateId", cancellationToken).ConfigureAwait(false);
          if ((templateParameter.ValueType == "P" || templateParameter.ValueType == "M" || templateParameter.ValueType == "R") && templateParameter.DataSource != null && portfolio != null)
          {
            templateParameter.DataSourceValues = await PopulateDataSourceValueAsync(ownerId, templateParameter.DataSource, templateParameter.DataValueField, templateParameter.DataTextField, cancellationToken, portfolio, valuePairs.GetValueOrDefault("model_id")?.Item2).ConfigureAwait(false);
          }

          var valueAssignment = await AssignParamValue(ownerId, templateParameter.DataType, templateParameter.ValueType, record, cancellationToken, parameter.Lid, parameter.TemplateParameterId).ConfigureAwait(false);
          if (valueAssignment.Count > 0)
          {
            parameter.SetPropertyValue(valueAssignment.Keys.FirstOrDefault(), valueAssignment.Values.FirstOrDefault());
          }

          if (!string.IsNullOrEmpty(parameter.ReferenceValue) && parameter.ValueType.Equals("REF", System.StringComparison.OrdinalIgnoreCase))
          {
            parameter.Description = await PopulateReferenceDescriptionAsync(ownerId, parameter.ReferenceValue, cancellationToken).ConfigureAwait(false);
          }
          else if (parameter.LookupCodes != null && parameter.LookupCodes.TryGetValue(record.GetValue<string>("param_value"), out var value))
          {
            parameter.Description = value; // fetch description from lookup code
          }
          else if (parameter.DataSourceValues != null && parameter.DataSourceValues.TryGetValue(record.GetValue<string>("param_value"), out var dataSourceValue))
          {
            parameter.Description = dataSourceValue; // fetch description from datasource value code
          }

          parameter.TemplateParameterId = templateParameter.Id;
          parameter.TemplateParameterCode = templateParameter.Code;
          parameter.Name = templateParameter.Name;
          parameter.DataType = templateParameter.DataType;
          parameter.Type = templateParameter.Type;
          parameter.Order = templateParameter.Order;
          parameter.ValueRequired = templateParameter.ValueRequired;
          parameter.ParameterValueType = templateParameter.ValueType;
          parameter.LookupCodes = templateParameter.LookupCodes;
          parameter.DataSource = templateParameter.DataSource;
          parameter.DataSourceValues = templateParameter.DataSourceValues;
          parameter.Purpose = templateParameter.Purpose;
          parameter.PurposeModifier = templateParameter.PurposeModifier;
          parameter.TypeDescription = templateParameter.TypeDescription;

        })
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);

      return parameters;
    }

