    public async Task<Core.Model.Calculation.Parameter> CreateOrUpdateCalculationBlockParameterAsync(string ownerId, Core.Model.Calculation.Parameter parameter, string modelId, int operationConfirmed, CancellationToken cancellationToken)
    {
      var paramValue = parameter.GetParamValue();
      parameter.Description = string.Equals(parameter?.ValueType, "REF", comparisonType: StringComparison.OrdinalIgnoreCase)
        ? await PopulateReferenceDescriptionAsync(ownerId, parameter.ReferenceValue, cancellationToken).ConfigureAwait(false)
        : parameter.Description;

      if (parameter.ParameterValueType == "B" && !string.IsNullOrEmpty(paramValue))// Boolean
      {
        int value = Convert.ToInt32(parameter.BooleanValue);
        paramValue = value.ToString(); // 0 or 1
        parameter.Description = value == 1 ? "Yes" : "No";
      }

      var (paramId, _) = await _sprocContext.PutSprocCommand<Core.Model.Calculation.Parameter>(ownerId)
        .WithParameters(
          new SprocParameter("dcb_param_id", parameter.Lid),
          new SprocParameter("dcbp_code", parameter.Code),
          new SprocParameter("dcb_id", parameter.BlockIdClassic),
          new SprocParameter("m_id", modelId),
          new SprocParameter("comments", parameter.Comments),
