    public async Task<IList<Core.Model.Calculation.Parameter>> BatchUpdateCalculationBlockParameterAsync(string ownerId, IList<Core.Model.Calculation.Parameter> parameters, string modelId, string blockId, int operationConfirmed, CancellationToken cancellationToken)
    {
      var paramsBuilder = new StringBuilder();
      var filter = $" block_id = {blockId}";
      foreach (var parameter in parameters)
      {
        var paramValue = parameter.GetParamValue();
        parameter.Description = string.Equals(parameter?.ValueType, "REF", comparisonType: StringComparison.OrdinalIgnoreCase)
          ? await PopulateReferenceDescriptionAsync(ownerId, parameter.ReferenceValue, cancellationToken).ConfigureAwait(false)
          : parameter.Description;
        if (parameter.ParameterValueType == "B" && !string.IsNullOrEmpty(paramValue))// Boolean
        {
          int value = Convert.ToInt32(parameter.BooleanValue);
          paramValue = value.ToString(); // 0 or 1
          parameter.Description = value == 1 ? "Yes" : "No";
        }
        paramsBuilder
          .Append(parameter.Lid).Append("#")
          .Append(parameter.ValueType).Append("#")
          .Append(paramValue).Append("#")
          .Append(parameter.Description).Append("#")
          .Append(parameter.ReferenceValue).Append("#")
          .Append("~");
      }

      string dcbParamIds = null;
      var (results, outputParams) = await _sprocContext.CustomSprocCommand<Core.Model.Calculation.Parameter>(ownerId, ModelingSprocContext.DC_CALCULATION_BLOCK_PARAMETERS_UPDATE)
       .WithParameters(
         new SprocParameter("m_id", modelId),
         new SprocParameter("dcb_id", blockId),
         new SprocParameter("parameter_string", paramsBuilder.ToString()),
         new SprocParameter("operation_confirmed", operationConfirmed),
         new SprocParameter("unit_separator", '#'),
         new SprocParameter("record_separator", '~'),
         new SprocParameter("dcb_param_ids", dcbParamIds, SprocParameterDirection.Output)
       )
       .ExecuteAsync(cancellationToken).ConfigureAwait(false);

      var blockParams = await GetCalculationBlockParametersAsync(ownerId, filter, null, cancellationToken).ConfigureAwait(false);
      //return only the params updated.
      return blockParams.Where(bp => parameters.Select(p => p.Lid).ToList().Contains(bp.Lid)).ToList();
    }

