    public async Task<IList<TestParameter>> GetTestParametersAsync(string ownerId, string filter, Portfolio portfolio, CancellationToken cancellationToken)
    {
      var valuePairs = _sprocTranslator.ParseForValuePairs<TestParameter>(filter);
      using var routerScope = DatabaseRouter.CreateScope(ownerId);
      Template template = null;

      var (parameters, _) = await _sprocContext.GetSprocCommand<TestParameter>(ownerId)
        .WithParameters(
          new SprocParameter("deal_test_param_id", valuePairs.GetValueOrDefault("id")?.Item2),
          new SprocParameter("deal_test_id", valuePairs.GetValueOrDefault("test_id")?.Item2),
          new SprocParameter("dtp_code", valuePairs.GetValueOrDefault("code")?.Item2),
          new SprocParameter("m_id", valuePairs.GetValueOrDefault("model_id")?.Item2),
          new SprocParameter("list_by_model", false)
        )
        .WithResultSetAsyncAction(async (testParam, record) =>
        {
          var templateCode = record.GetValue<string>("template_code");
          var templateParameterCode = record.GetValue<string>("template_parameter_code");

          //var indexOfExistingParam = parameters.FindIndex(x => x.TemplateParameterIdClassic == record.GetValue<string>("test_param_id"));

          template ??= await this.GetByCodeAsync<Template>(templateCode, Guid.Empty, null, cancellationToken).ConfigureAwait(false);
          var templateParameter = await this.GetByCodeAsync<TemplateParameter>(templateParameterCode, template.Id, "TemplateId", cancellationToken).ConfigureAwait(false);
          if ((templateParameter.ValueType == "P" || templateParameter.ValueType == "M" || templateParameter.ValueType == "R") && templateParameter.DataSource != null && portfolio != null)
          {
            templateParameter.DataSourceValues = await PopulateDataSourceValueAsync(ownerId, templateParameter.DataSource, templateParameter.DataValueField, templateParameter.DataTextField, cancellationToken, portfolio, valuePairs.GetValueOrDefault("model_id")?.Item2).ConfigureAwait(false);
          }
          testParam.Type = templateParameter.Type;
          testParam.ValueRequired = templateParameter.ValueRequired;
          testParam.TemplateParameterId = templateParameter.Id;
          testParam.TemplateParameterCode = templateParameter.Code;
          testParam.LookupCodes = templateParameter.LookupCodes;
          testParam.DataSource = templateParameter.DataSource;
          testParam.DataSourceValues = templateParameter.DataSourceValues;
          testParam.Purpose = templateParameter.Purpose;
          testParam.PurposeModifier = templateParameter.PurposeModifier;
          testParam.TypeDescription = templateParameter.TypeDescription;

          var valueAssignment = await AssignParamValue(ownerId, record.GetValue<string>("data_type"), record.GetValue<string>("value_type"), record, cancellationToken, testParam.Lid, testParam.TemplateParameterId).ConfigureAwait(false);
          if (valueAssignment.Count > 0)
          {
            testParam.SetPropertyValue(valueAssignment.Keys.FirstOrDefault(), valueAssignment.Values.FirstOrDefault());
          }

          if (!string.IsNullOrEmpty(testParam.ReferenceValue) && testParam.ValueType.Equals("REF", System.StringComparison.OrdinalIgnoreCase))
          {
            testParam.Description = await PopulateReferenceDescriptionAsync(ownerId, testParam.ReferenceValue, cancellationToken).ConfigureAwait(false);
          }
          else if (testParam.LookupCodes != null && testParam.LookupCodes.TryGetValue(testParam.Description, out var value))
          {
            testParam.Description = value; // fetch description from lookup code
          }
          else if (testParam.DataSourceValues != null && testParam.DataSourceValues.TryGetValue(testParam.Description, out var dataSourceValue))
          {
            testParam.Description = dataSourceValue; // fetch description from datasource value code
          }
        })
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);

      return parameters;
    }

