    public async Task<IList<TestEligibilityCriteria>> GetEligibilityCriteriaTestsAsync(string ownerId, string filter, CancellationToken cancellationToken)
    {
      var valuePairs = _sprocTranslator.ParseForValuePairs<TestEligibilityCriteria>(filter);
      bool.TryParse(valuePairs.GetValueOrDefault("exclude_expressions")?.Item2 ?? "false", out bool excludeExpressions);
      using var routerScope = DatabaseRouter.CreateScope(ownerId);

      var (ecTests, _) = await _sprocContext.GetSprocCommand<TestEligibilityCriteria>(ownerId)
        .WithParameters(
          new SprocParameter("ec_test_id", valuePairs.GetValueOrDefault("id")?.Item2),
          new SprocParameter("ect_code", valuePairs.GetValueOrDefault("code")?.Item2),
          new SprocParameter("m_id", valuePairs.GetValueOrDefault("model_id")?.Item2),
          new SprocParameter("entity_id", valuePairs.GetValueOrDefault("portfolio_id")?.Item2),
          new SprocParameter("list_by_model", false)
        )
        .WithResultSetAsyncAction(async (instance, record) =>
        {
          TemplateEligibilityCriteria criteria = null;
          var ecTestType = record.GetValue<string>("ec_test_type").Trim();
          if (ecTestType == "S" && !string.IsNullOrEmpty(record.GetValue<string>("ec_code")))
          {
            criteria = await this.GetByCodeAsync<TemplateEligibilityCriteria>(record.GetValue<string>("ec_code"), Guid.Empty, null, cancellationToken).ConfigureAwait(false);
          }
          instance.CriteriaId = criteria != null ? criteria.Id : Guid.Empty;
          instance.CriteriaCode = criteria?.Code;
        })
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);

      if (!excludeExpressions)
      {
        // let's kick off the applicability and criteria expression population concurrently across all the list of ecTests.
        await Task.WhenAll(new List<Task>
        {
          PopulateApplicabilityExpressionsAsync(ownerId, ecTests, cancellationToken),
          PopulateCriteriaExpressionsAsync(ownerId, ecTests, cancellationToken)
        }).ConfigureAwait(false);
      }

      return ecTests;
    }

