using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Solvas.Owner.Client.SqlServer;
using Solvas.Owner.Client.SqlServer.Abstractions;
using SolvasAm.Common.Database;
using SolvasAm.Common.Extensions;
using SolvasFabric.DistributedLocking.Abstractions;
using System;
using System.Threading;
using System.Threading.Tasks;

namespace SolvasAmCompliance.Modeling.Infrastructure.EntityFramework
{
  public abstract class ModelingRepositoryBase : RepositoryItemsBase<ModelingDbContext>
  {
    protected IDatabaseRouter DatabaseRouter { get; }
    private readonly IDistributedLockManager _distributedLockManager;
    private readonly IDistributedLockingKeyProvider _distributedLockingKeyProvider;
    private readonly DbInitializer _dbInitializer;

    // Reference to a logger.
    protected ILogger<ModelingRepository> Logger { get; }

    // Reference to our singleton service provider.
    // Will be used to create scopes for instantiating ModelingDbContext.
    protected IServiceProvider ServiceProvider { get; }

    /// <summary>
    /// Instantiate a ModelingRepositoryBase instance.
    /// </summary>
    protected ModelingRepositoryBase(IServiceProvider serviceProvider, IDistributedLockManager distributedLockManager, IDistributedLockingKeyProvider distributedLockingKeyProvider, ILogger<ModelingRepository> logger, IDatabaseRouter router, DbInitializer dbInitializer, SolvasFabric.Runtime.Extensions.IAmbientStateManager stateManager, SolvasFabric.Linq.Extensions.Filter.IFilterTranslator filterTranslator, SolvasFabric.Linq.Extensions.Order.IOrderTranslator orderTranslator) : base(serviceProvider, stateManager, filterTranslator, orderTranslator, logger)
    {
      ServiceProvider = serviceProvider;
      Logger = logger;
      DatabaseRouter = router;
      _distributedLockManager = distributedLockManager;
      _distributedLockingKeyProvider = distributedLockingKeyProvider;
      _dbInitializer = dbInitializer;
    }

    /// <summary>
    /// A call helper which hides away the set up of backoff, database context and transaction.
    /// </summary>
    protected async Task RepoCallAsync(string callName, Func<ModelingDbContext, Task> action, CancellationToken cancellationToken)
    {
      var contextFactory = ServiceProvider.GetRequiredService<IAsyncDbContextFactory<ModelingDbContext>>();
      await using var context = await contextFactory.CreateDbContextAsync(cancellationToken).ConfigureAwait(false);
      var executionStrategy = context.Database.CreateExecutionStrategy();

      // Note regarding the cancellation token passed into the lambda of ExecuteAsync:
      // The MS docs on ExecuteAsync state that the cancellation token passed into ExecuteAsync is:
      // "A cancellation token used to cancel the retry operation, but not operations that are already in flight or that already completed successfully."
      // This means that the cancellation token passed into the lambda must be different than the one passed into ExecuteAsync.
      // We want to be able to cancel actions in flight using the same cancellation token as the one used to cancel the retry operations.
      // So we leave only one option to the user of RepoCallAsync and its action lambda - to use the cancellation token as the one passed into RepoCallAsync
      // by capturing the cancellation token variable in the body of the action lambda.
      await executionStrategy.ExecuteAsync(async (_) =>
      {
        await using var innerContext = await contextFactory.CreateDbContextAsync(cancellationToken).ConfigureAwait(false);
        await action(innerContext).ConfigureAwait(false);
      },
      cancellationToken).ConfigureAwait(false);
    }

    /// <summary>
    /// Perform repository initialization steps such as running EF migrations or creating MongoDB databases and collections.
    /// </summary>
    public Task InitializeAsync(CancellationToken cancellationToken)
    {

      // Migrate all databases using the router.
      // In a normal Flaming Volcano project we would do this directly for a single database.
      // Instead, use the router to run migrations on all databases.

      // Migrate the database using a distributed lock to prevent conflicts with other services'
      // migration processes running against the same database.

      // Receive new owner events through the channel and run migrations real-time when
      // new owners get added. However, this happens on a dedicated task since the await on the
      // channel should not block the application.

      var subscription = DatabaseRouter.SubscribeToOwnerEvent();

      _ = Task.Run(async () =>
      {
        await foreach (var notification in subscription.Reader.ReadAllAsync(cancellationToken))
        {
          try
          {
            var lockKey = $"fabric/ef-migration-locks/{_distributedLockingKeyProvider.Key}";
            Logger.Info("Obtaining a lock to run migrations using key {lockKey}...", lockKey);
            await using (await _distributedLockManager.WaitToAcquireAsync(lockKey, cancellationToken).ConfigureAwait(false))
            {
              Logger.Info("A new owner {owner} has been added. Running the database migration now", notification.OwnerId);
              await DatabaseRouter.RunOnOwnerContextsAsync<ModelingDbContext>(notification.OwnerId, _dbInitializer.InitializeAsync, cancellationToken: CancellationToken.None).ConfigureAwait(false);
            }
          }
          catch (Exception ex)
          {
            Logger.Error(ex, "An error occured while running EF Core migrations for {owner}.", notification.OwnerId);
          }
        }
      }, cancellationToken);

      return Task.CompletedTask;
    }
  }
}

