    private async Task<ListResult<T>> ListItemsAsync<T, U>(SolvasAm.Common.GrpcApi.V1.ListRequest request, ServerCallContext context, RepoQuery<U> repoQuery = null) where T : class, Google.Protobuf.IMessage<T> where U : Identity
    {
      var permissions = await _oidcResourceAuthorizer.GetUserPermissionsAsync(_credentials.CurrentValue.ClientId, context, _logger).ConfigureAwait(false);
      if (request.MetaOnly.HasValue && request.MetaOnly.Value)
        return new ListResult<T>(Enumerable.Empty<T>().ToList(), 0, permissions);

      var resourceName = ResourceName.Parse<T>(request.Parent, false);
      using IRouterScope routerScope = _databaseRouter.CreateScope(resourceName.OwnerId);
      int? pageSize = request.PageSize > 0 ? request.PageSize : default(int?);
      var modelItems = await _repository.ListAsync<U>(request.Skip, pageSize, request.OrderBy, request.Filter, context.CancellationToken, repoQuery).ConfigureAwait(false);
      var grpcItems = modelItems.MapToProto<T, U>(_mapper, request.Parent, false).ToList();
      return new ListResult<T>(grpcItems, modelItems.TotalSize, permissions);
    }

    private async Task<T> CreateItemAsync<T, U>(T grpcItem, ResourceName resourceName, Dictionary<string, object> callingValues, ServerCallContext context) where T : Google.Protobuf.IMessage<T> where U : Identity
    {
      grpcItem.SetPropertyValue("Id", string.Empty);
      grpcItem.SetPropertyValue("Lid", 0);
      var validator = _serviceProvider.GetRequiredService<IValidator<U>>();
      var modelItem = await _mapper.MapToModelAndValidate(grpcItem, ApiRequestType.CREATE, validator, callingValues, context.CancellationToken).ConfigureAwait(false);

      var newModelItem = await _repository.CreateItemAsync(modelItem, false, context.CancellationToken).ConfigureAwait(false);

      var newGrpcItem = _mapper.Map<T>(newModelItem);
      newGrpcItem.SetPropertyValue("Name", ResourceName.Format<T>(resourceName.OwnerId, newModelItem.Id.ToString(), resourceName.Parent));
      return newGrpcItem;
    }

    private async Task<T> UpdateItemAsync<T, U>(T grpcItem, ResourceName resourceName, FieldMask updateMask, ServerCallContext context, Dictionary<string, object> callingValues = null, FieldMask.MergeOptions mergeOptions = null) where T : Google.Protobuf.IMessage<T> where U : Identity
    {
      var validator = _serviceProvider.GetRequiredService<IValidator<U>>();
      grpcItem.SetPropertyValue("Id", resourceName.Id);
      try
