    [AuthorizeOwner("model-list.create", NameProperty = "Parent")]
    [ValidateRequest(ApiRequestType.CREATE)]
    public async override Task<ComplianceModel> CreateComplianceModel(CreateComplianceModelRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<ComplianceModel>(request.Parent, false);

      var grpcItem = request.ComplianceModel;
      grpcItem.Name = string.Empty;
      grpcItem.Id = string.Empty;

      var portfolio = await GetPortfolioAsync(resourceName, context).ConfigureAwait(false);
      grpcItem.PortfolioId = portfolio.Lid.ToString();

      grpcItem = await grpcItem.AutoAssignUniqueCodeClassic(resourceName.OwnerId, ComplianceEnum.CodeType.Model, grpcItem.Description, _repository.GetUniqueCodeClassic, grpcItem.PortfolioId, nameof(grpcItem.Code), null, context.CancellationToken).ConfigureAwait(false);

      try
      {
        var existingItem = await _repository.GetComplianceModelByCodeAsync(resourceName.OwnerId, grpcItem.Code, portfolio.Lid.ToString(), context.CancellationToken).ConfigureAwait(false);
        RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Requested code already in use.");
      }
      catch (ItemNotFoundException)
      {
        var callingValues = new Dictionary<string, object>
        {
          { OWNER_ID_LITERAL, resourceName.OwnerId },
          { "PortfolioId", grpcItem.PortfolioId }
        };
        await _repository.LockAllComplianceModelsAsync(
            resourceName.OwnerId,
            grpcItem.PortfolioId,
            request.OperationConfirmed,
            context.CancellationToken
            ).ConfigureAwait(false);

        var validator = _serviceProvider.GetRequiredService<IValidator<Core.Model.ComplianceModel.Model>>();
        var modelItem = await _mapper.MapToModelAndValidate(grpcItem, ApiRequestType.CREATE, validator, callingValues, context.CancellationToken).ConfigureAwait(false);

        return await CreateOrUpdateComplianceModelAsync(
        resourceName,
        modelItem,
        request.OperationConfirmed,
        context
        ).ConfigureAwait(false);
      }

      return default;
    }

    [AuthorizeOwner("model-list.update", NameProperty = "ComplianceModel.Name")]
    [ValidateRequest(ApiRequestType.UPDATE)]
    public async override Task<ComplianceModel> UpdateComplianceModel(UpdateComplianceModelRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<ComplianceModel>(request.ComplianceModel.Name);
      var grpcItem = request.ComplianceModel;
      grpcItem.Id = resourceName.Id;

      var portfolio = await GetPortfolioAsync(resourceName, context).ConfigureAwait(false);
      grpcItem.PortfolioId = portfolio.Lid.ToString();

      try
      {
        var existingItem = await _repository.GetComplianceModelByIdAsync(resourceName.OwnerId, grpcItem.Id, context.CancellationToken).ConfigureAwait(false);
        var callingValues = new Dictionary<string, object>
        {
          { OWNER_ID_LITERAL, resourceName.OwnerId },
          { "PortfolioId", grpcItem.PortfolioId }
        };

        if (grpcItem.State == "U") //lock any other open model
        {
          await _repository.LockAllComplianceModelsAsync(
            resourceName.OwnerId,
            grpcItem.PortfolioId,
            request.OperationConfirmed,
            context.CancellationToken
            ).ConfigureAwait(false);
        }

        var modelItem = await UpdateItemClassicAsync(grpcItem, existingItem, resourceName, request.UpdateMask, context, callingValues).ConfigureAwait(false);

        return await CreateOrUpdateComplianceModelAsync(
          resourceName,
          modelItem,
          request.OperationConfirmed,
          context
        ).ConfigureAwait(false);
      }
      catch (ItemNotFoundException)
      {
        RpcExceptionHelper.ThrowWithStatus(StatusCode.NotFound, $"\"{grpcItem.Name}\" not found.");
      }

      return default;
    }

