    public async override Task<Empty> BatchDeleteComplianceModels(SolvasAm.Common.GrpcApi.V1.BatchDeleteRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<ComplianceModel>(request.Parent, false);
      SolvasAmHelper.ValidateConfirmed(1, request.OperationConfirmed, SolvasAmHelper.GenerateDeleteConfirmationMessage(request.Names.Count, "compliance model"), "Delete Compliance Models");

      var errors = new List<string>();
      foreach (var name in request.Names)
      {
        var sourceResourceName = ResourceName.Parse<ComplianceModel>(name);
        try
        {
          await _repository.DeleteComplianceModelsAsync(
            resourceName.OwnerId,
            new[] { new Core.Model.ComplianceModel.Model { Lid = Convert.ToInt64(sourceResourceName.Id) } },
            request.OperationConfirmed,
            context.CancellationToken
        ).ConfigureAwait(false);
        }
        catch (Exception ex)
        {
          errors.Add($"Failed to delete model with Id {sourceResourceName.Id}: {ex.Message}");
        }
      }

      if (errors.Any())
      {
        var errorMessage = string.Join("\n", errors);
        RpcExceptionHelper.ThrowWithStatus(StatusCode.FailedPrecondition, $"The following models could not be deleted:\n{errorMessage}. Please check your data and try again");
      }
      return new Empty();
    }

    [AuthorizeOwner("model-list.create", NameProperty = "Parent")]
    [ValidateRequest(ApiRequestType.COPY)]
    public async override Task<CopyComplianceModelsResponse> CopyComplianceModels(SolvasAm.Common.GrpcApi.V1.CopyRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<ComplianceModel>(request.Parent, false);
      var sourceModelIds = new List<string>();
      var response = new CopyComplianceModelsResponse();

      var portfolio = await GetPortfolioAsync(resourceName, context).ConfigureAwait(false);

      foreach (var name in request.Names)
      {
        var sourceResourceName = ResourceName.Parse<ComplianceModel>(name);
        sourceModelIds.Add(sourceResourceName.Id);
      }

      var lids = await _repository.CopyComplianceModelsAsync(
        resourceName.OwnerId,
        sourceModelIds,
        portfolio.Lid.ToString(),
        request.OperationConfirmed,
        context.CancellationToken
        ).ConfigureAwait(false);

      foreach (var lid in lids)
      {
        response.ComplianceModels.Add(new ComplianceModel() { Lid = Convert.ToInt64(lid), Name = ResourceName.Format<ComplianceModel>(resourceName.OwnerId, lid, resourceName.Parent) });
      }

      //Unlock the first Model from List of Copied Models
      if (lids.Count > 0)
      {
        var model = await _repository.GetComplianceModelByIdAsync(resourceName.OwnerId, lids[0], context.CancellationToken).ConfigureAwait(false);
        if (model.State == "L")
        {
          await _repository.ToggleComplianceModelLockAsync(
            resourceName.OwnerId,
            model,
            request.OperationConfirmed,
            context.CancellationToken
            ).ConfigureAwait(false);
        }
      }

      return response;
    }

