      var newGrpcItem = _mapper.Map<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(newModelItem);
      newGrpcItem.Name = ResourceName.Format<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(resourceName.OwnerId, newModelItem.Lid.ToString(), resourceName.Parent);
      return newGrpcItem;
    }

    #endregion

    private async Task<SolvasAmPortfolio.Organizations.Shared.Model.Portfolio.Portfolio.Portfolio> GetPortfolioAsync(ResourceName resourceName, ServerCallContext context)
    {
      string portfolioId = "portfolio";
      try
      {
        portfolioId = resourceName.GetId<SolvasAmPortfolio.Organizations.GrpcApi.V1.Portfolio>();
        return await _repository.GetPortfolioByIdAsync(resourceName.OwnerId, portfolioId, context.CancellationToken).ConfigureAwait(false);
      }
      catch (ItemNotFoundException)
      {
        RpcExceptionHelper.ThrowWithStatus(StatusCode.NotFound, $"\"{portfolioId}\" not found.");
      }

      return default;
    }

    private async Task<IList<string>> GetPortfolioIdsAsync(ResourceName resourceName, IList<Guid> portfolioIds, ServerCallContext context)
    {
      var results = new List<string>();
      if (portfolioIds == null || portfolioIds.Count() == 0)
        return null;

      foreach (var portfolioId in portfolioIds)
      {
        try
        {
          var portfolio = await _repository.GetPortfolioByIdAsync(resourceName.OwnerId, portfolioId.ToString(), context.CancellationToken).ConfigureAwait(false);
          results.Add(portfolio.Lid.ToString());
        }
        catch (ItemNotFoundException)
        {
          RpcExceptionHelper.ThrowWithStatus(StatusCode.NotFound, $"\"{portfolioId}\" not found.");
        }
      }
      return results;
    }

    private HydrateOption GetHydrateOptionFromFilter<T>(SolvasAm.Common.GrpcApi.V1.ListRequest listRequest)
    {
      var valuePairs = _sprocTranslator.ParseForValuePairs<T>(listRequest.Filter);
      var hydrateStr = valuePairs.GetValueOrDefault("hydrate")?.Item2;
      if (!System.Enum.TryParse<HydrateOption>(hydrateStr ?? "lite", true, out var hydrateOption))
      {
        throw new InvalidCastException($"Invalid HydrateOption value '{hydrateStr}' for filter field 'hydrate'");
      }
      return hydrateOption;
    }
  }
