using SolvasAmCompliance.Modeling.Shared.CacheDataProvider;
using SolvasFabric.Grpc.Client;

namespace SolvasAmCompliance.Modeling.Shared
{
  public static class ServiceCollectionExtensions
  {
    public static IServiceCollection AddComplianceModelingCache<T, U>(this IServiceCollection services, IConfiguration configuration, string clientId = null) where T : Identity where U : DbContext
    {
      services.AddSingleton<IObjectMap<T>, IdentityObjectMap<T>>();
      services.Configure<CacheOptions<T>>(configuration.GetSection("memoryCache:complianceModeling"));
      services.AddSingleton<IObjectMapMonitoringHost<T>, ObjectMapMonitoringHost<T>>();

      var useWassupsEvents = configuration.GetValue<bool>("memoryCache:complianceModeling:useWassupsEvents");
      if (useWassupsEvents)
      {
        var cacheableTypeCollection = services.GetOrCreateSingleton<WassupsCacheableTypeDescriptorCollection>();
        // if no object map has been previously added, add a consumer handler. We do not need a handler for each type of oject we cache.
        if (cacheableTypeCollection.Count == 0)
          services.AddWassupsAsyncConsumer<WassupsModelingCacheConsumerHandler, WassupsEventCacheOffsetProvider>("compliance-modeling-wassups", clientId, new string[] { });

        var cacheableTypeDescriptor = new WassupsCacheableTypeDescriptor()
        {
          EntityType = typeof(T)
        };
        cacheableTypeCollection.Add(cacheableTypeDescriptor);
        services.AddSingleton<IObjectMapDataProvider<T>, WassupsEventMapDataProvider<T>>()
          .AddSingleton<WassupsEventCacheOffsetProvider>();
      }
      else
      {
        var useWassupsTables = configuration.GetValue<bool>("memoryCache:complianceModeling:useWassupsTables");
        if (useWassupsTables)
        {
          services.AddSingleton<IObjectMapDataProvider<T>, WassupsBasedMapDataProvider<T, U>>();
        }
        else
        {
          services.AddSingleton<IObjectMapDataProvider<T>, ServiceBasedMapDataProvider<T>>()
          //Add a client to our own service. This is for the RuleCache to work.
          .AddApiClient<ModelingService.ModelingServiceClient>();
        }
      }
      return services;
    }
  }
}

