  public abstract class ModelElement : Identity, IEquatable<ModelElement>
  {
    public string ModelIdClassic { get; set; }
    public string CopySourceIdClassic { get; set; }

    public Guid ModelId { get; set; }
    public string ModelCode { get; set; }
    public Guid? CopySourceId { get; set; }
    public string CopySourceCode { get; set; }
    public string ImportCode { get; set; }
    public bool NeedsReview { get; set; }

    //derived values
    public string CopySourceDescription { get; set; }

    public bool Equals(ModelElement other)
    {
      if (other == null)
        return false;

      return (ModelId == other.ModelId) && (Id == other.Id);
    }

    public override bool Equals(Object obj)
    {
      if (obj == null)
        return false;

      if (!(obj is ModelElement modelEl))
        return false;
      else
        return Equals(modelEl);
    }

    public override int GetHashCode()
    {
      return (Id.GetHashCode() * 17) + ModelId.GetHashCode();
    }
  }
