namespace SolvasAmCompliance.Modeling.Grpc.Internal
{
  public class Startup : IStartup
  {
    public IConfiguration Configuration { get; }

    public Startup()
    {
      Configuration = BuildConfiguration();
    }

    // This method gets called by the runtime. Use this method to add services to the Dependency Injection container.
    public void ConfigureServices(IServiceCollection serviceCollection)
    {
      serviceCollection
        // Add automatic generation of Wassup events based on Entity Framework change detection.
        .AddSolvasFabricEntityFrameworkWassup(Configuration, noTrackingTypes: new Type[]
        {
          // Remove data-seed-history-update noise from our published Wassup event streams.
          typeof(SolvasAm.Common.Models.DataSeedRecord),
          typeof(SolvasAm.Common.Model.ReferenceData.LookupType),
          typeof(SolvasAm.Common.Model.ReferenceData.LookupItem),
          typeof(SolvasAm.Common.Model.ReferenceData.LookupItemGroup),
          typeof(SolvasAm.Common.Model.ReferenceData.LookupCompositionLink),
        })

        // Add Solvas Fabric host infrastructure.
        .AddSolvasFabricServiceHost(Configuration, new ServiceHostOptions { EnableOidc = true })
        // Add Solvas Fabric client infrastructure.
        .AddSolvasFabricServiceClient(Configuration, new ServiceClientOptions { EnableOidc = true })
        // Add distributed locking manager.
        .AddDistributedLockingInfrastructure(Configuration)
        .AddDistributedLockingKeyProvider(Configuration)
        // wassups integration
        .AddSingleton<IWassupEventScopeDetector, ModelingWassupEventScopeDetector>()
        .AddSingleton<IWassupEventCollector, SolvasAm.Common.Wassups.SolvasAmWassupsEventCollector>()
        // Make this service a Wassup consumer.
        .AddFabricWassupsConsumerHost(Configuration)
        // Override the default Wassup offset proivider.
        // Note that this must be called after AddFabricWassupsConsumerHost.
        .AddSingleton<IWassupsEventOffsetProvider, WassupsConsumerEventOffsetProvider<ModelingDbContext>>()
        // Register domain data Wassup consumer.
        .AddWassupsAsyncConsumer<WassupDomainDataConsumerHandler<ModelingDbContext>>("solvasam-domaindata-wassups", "compliance-modeling", new string[] { })
        // Register our service API with the gRPC host.
        .AddApiClient<Fabric.Wassups.GrpcApi.V1.WassupsService.WassupsServiceClient>()
        // Register the client stub which will give us access to services which implement data seed registries.
        .AddApiClient<SolvasAm.DomainData.GrpcApi.V1.DomainDataService.DomainDataServiceClient>()
        .AddApiClient<SolvasAmPortfolio.Organizations.GrpcApi.V1.OrganizationsService.OrganizationsServiceClient>()
        //Add a client to our own service. This is for the RuleCache to work.
        .AddApiClient<ModelingService.ModelingServiceClient>()
        .AddHostApi<ModelingServiceImpl>(ModelingService.BindService, ModelingService.Descriptor)
        // Register automapper profiles.
        .AddSingleton<AutoMapper.IConfigurationProvider>(_ => new MapperConfiguration(cfg =>
        {
          cfg.AddProfile<SolvasFabricAutoMapperProfile>();
          cfg.AddProfile<GrpcToModelAutoMapperProfile>();
          cfg.AddProfile<DomainDataSharedModelProfile>();
          cfg.Advanced.AllowAdditiveTypeMapCreation = true;
        }))
        // Register automapper.
        .AddTransient<IMapper>(services => new Mapper(services.GetRequiredService<AutoMapper.IConfigurationProvider>()))
        .AddSingleton<SolvasAm.Common.Validators.IValidationModeProvider, SolvasAm.Common.Validators.ConfigBasedValidationModeProvider>()
        // Register our validators.
        .AddValidatorsFromAssemblyContaining<Core.Validators.ComplianceModel.ModelValidator>(ServiceLifetime.Transient)
        .AddValidatorsFromAssemblyContaining<SolvasAm.Common.Validators.Expression.RuleValidator>(ServiceLifetime.Transient)
        //solvas-owner integration
        .AddApiClient<Solvas.Owner.GrpcApi.V1.OwnerService.OwnerServiceClient>()
        .AddAsyncWassupProducerDbContextFactory<ModelingDbContext>(Configuration, "compliance-modeling")
        .AddSingleton<DbInitializer>();

      // Add translator to translate order expressions to chained EF IOrderedQueryables.
      SolvasFabric.Linq.Extensions.ServiceCollectionExtensions.AddEntityFrameworkOrderTranslator(serviceCollection);

      // In a normal Flaming Volcano project, we would set the options action directly here.
      // When using the router, use the options action provided by the router to enable dynamic routing.      
      serviceCollection
        .AddEntityFrameworkFilterTranslator()
        .AddSingleton<IMemberNameResolver, AutoMapperBasedProtoMemberNameResolver>()
        .AddSingleton<ModelingRepository>()
        .AddSingleton<IModelingRepository>(svcProvider => svcProvider.GetRequiredService<ModelingRepository>())
        .AddSingleton<IRepositoryItems>(svcProvider => svcProvider.GetRequiredService<ModelingRepository>())
        // Register the standard data seed registry repository implementation.
        .AddEntityFrameworkDataSeedRegistryRepository<ModelingDbContext>()
        // Adds a lookup items cache and monitor. The cache is a lookup type to lookupItems store.
        // The cache monitor builds the lookup cache and keeps refreshing it at fixed intervals
        // Default refresh period is 1 hour that can be overridden by memoryCache:referenceDataCache:refreshIntervalInSeconds in app settings
        .AddLookupItemsCache<ModelingDbContext>(Configuration, "compliance-modeling-cache")
        // Adds an object cache and monitor. The cache is an id-object store.
        // The cache monitor builds the object cache and keeps refreshing it at fixed intervals
        // Default refresh period is 1 hour that can be overridden by memoryCache:domainDataCache:refreshIntervalInSeconds in app settings
        .AddDomainDataCache<SolvasAm.DomainData.Shared.Model.DataDictionary.Field, ModelingDbContext>(Configuration, "compliance-modeling-cache")
        .AddDomainDataCache<SolvasAm.DomainData.Shared.Model.ReferenceData.FunctionDefinition, ModelingDbContext>(Configuration, "compliance-modeling-cache")
        .AddComplianceModelingCache<SolvasAm.Common.Model.Expression.Rule, ModelingDbContext>(Configuration, "compliance-modeling-cache")
        .AddPortfolioCache<ModelingDbContext>(Configuration)
        .AddHostInterceptor<ValidateRequestInterceptor>(0)
        .AddHostInterceptor<InjectGenericScopeInterceptor>(1)
        .AddHostInterceptor<ResourceNameAuthorizationInterceptor>(2);

      serviceCollection.AddSprocContext<ModelingSprocContext>();
      serviceCollection.Configure<FeatureFlags>(Configuration.GetSection("featureFlags"));
    }

    // This method gets called by the runtime. Use this method to configure the services.
    public void Configure(IServiceProvider serviceProvider)
    {
      // Set up logging and OIDC self-registration.
      serviceProvider
        .ConfigureSolvasFabricServiceHost<Startup>()
        .ConfigureSolvasFabricServiceClient();

      // Register application startup and shutdown events.
      var applicationLifetime = serviceProvider.GetRequiredService<IApplicationLifetime>();

      // Get a reference to the Wassup consumer host.
      var wassupsConsumerHost = serviceProvider.GetRequiredService<IWassupsConsumerHost>();

      // Get reference to the in-memory caches
      var lookupItemsCacheMonitor = serviceProvider.GetRequiredService<IObjectLookupMonitoringHost<SolvasAm.Common.Model.ReferenceData.LookupItem>>();
      var dataDictionaryFieldsCacheMonitor = serviceProvider.GetRequiredService<IObjectMapMonitoringHost<SolvasAm.DomainData.Shared.Model.DataDictionary.Field>>();
      var functionDefCacheMonitor = serviceProvider.GetRequiredService<IObjectMapMonitoringHost<SolvasAm.DomainData.Shared.Model.ReferenceData.FunctionDefinition>>();
      var portfolioCacheMonitor = serviceProvider.GetRequiredService<IObjectMapMonitoringHost<SolvasAmPortfolio.Organizations.Shared.Model.Portfolio.Portfolio.Portfolio>>();
      var complianceModelingRulesCacheMonitor = serviceProvider.GetRequiredService<IObjectMapMonitoringHost<SolvasAm.Common.Model.Expression.Rule>>();

      //*******************
      // Startup code.
      //*******************
      applicationLifetime.ApplicationStarted.Register(() =>
      {
        // Before wassup consumer is started, we need to build the caches. Since the caches do not have its own wassupeventOffsetProvider, they will be using
        // the offsetProvider registereed for the local tables. But the offset for in-memory caches should start at 0.
        // on an app restart, the wassup local tables will have the data and hence a non-zero offset. So, the consumer to build the cache will not get any messages.
        // we can build the cache from local wassup tables and then rely on the consumer handler to keep it updated just like the wassup tables.
        // In the future, if the fabric wassup infrastructure provides an offset provider per consumerhandler registered, we can avoid this step altogether.
        // Lets wait for 30 seconds for the cache to build before we start the wassup consumer?
        //var domainDataCacheBuildTask = _domainDataCache.BuildAsync(new CancellationTokenSource(30_000).Token);
        //Task.WhenAll(domainDataCacheBuildTask).GetAwaiter().GetResult();

        // Start Wassup consumer host.
        wassupsConsumerHost.StartAsync().GetAwaiter().GetResult();

        // Put other service startup code here.
        lookupItemsCacheMonitor.StartAsync(applicationLifetime.ApplicationStopping).GetAwaiter().GetResult();
        dataDictionaryFieldsCacheMonitor.StartAsync(applicationLifetime.ApplicationStopping).GetAwaiter().GetResult();
        functionDefCacheMonitor.StartAsync(applicationLifetime.ApplicationStopping).GetAwaiter().GetResult();
        portfolioCacheMonitor.StartAsync(applicationLifetime.ApplicationStopping).GetAwaiter().GetResult();
        complianceModelingRulesCacheMonitor.StartAsync(applicationLifetime.ApplicationStopping).GetAwaiter().GetResult();
      });


      //*******************
      // Shutdown code.
      //*******************
      applicationLifetime.ApplicationStopping.Register(() =>
      {
        // Stop the Wassup consumer host.
        wassupsConsumerHost.StopAsync().GetAwaiter().GetResult();

        // Put your service shutdown code here.
        lookupItemsCacheMonitor.StopAsync(CancellationToken.None).GetAwaiter().GetResult();
        dataDictionaryFieldsCacheMonitor.StopAsync(CancellationToken.None).GetAwaiter().GetResult();
        functionDefCacheMonitor.StopAsync(CancellationToken.None).GetAwaiter().GetResult();
        portfolioCacheMonitor.StopAsync(CancellationToken.None).GetAwaiter().GetResult();
        complianceModelingRulesCacheMonitor.StopAsync(CancellationToken.None).GetAwaiter().GetResult();

      });
    }

    /// <summary>
    /// Build an IConfiguration instance.
    /// </summary>
    /// <returns></returns>
    public static IConfiguration BuildConfiguration()
    {
      return SolvasFabricConfiguration.Build("./config/");
    }
  }
