using FluentValidation;
using SolvasAm.Common.Database.Abstractions;
using SolvasAm.Common.Validators;
using System.Linq;

namespace SolvasAmCompliance.Modeling.Core.Validators.ComplianceModel
{
  public class ModelValidator : IdentityValidator<Core.Model.ComplianceModel.Model>
  {
    private readonly IModelingRepository _repository;

    public ModelValidator(IModelingRepository repository, IValidationModeProvider modeProvider, IRepositoryItems itemsProvider) : base(modeProvider, itemsProvider, true)
    {
      _repository = repository;

      RuleFor(m => m.PortfolioIdClassic).NotEmpty();
      RuleFor(m => m.PortfolioCode).MaximumLength(100);
      RuleFor(m => m.SequenceCode).MaximumLength(100);
      RuleFor(m => m.State).NotEmpty().MaximumLength(100);
      RuleFor(m => m.Purpose).NotEmpty().MaximumLength(100);
      RuleFor(m => m.User).MaximumLength(255);
      RuleFor(m => m.Description).NotEmpty().MaximumLength(255);
      RuleFor(m => m.Comments).MaximumLength(255);
      RuleFor(m => m).Custom((model, context) =>
      {
        if (model.EffectivePeriodEndDate?.Date.CompareTo(model.EffectivePeriodBeginDate?.Date) < 0)
        {
          context.AddFailure("EffectivePeriodEndDate", "End date must be greater than or equal to Begin date");
        }
      });
      RuleFor(m => m.EffectivePeriodBeginDateReference).MaximumLength(100);
      RuleFor(m => m.EffectivePeriodEndDateReference).MaximumLength(100);

      RuleFor(m => m).MustAsync(async (model, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic)
        {
          return true;
        }

        if (model.State == "U" && _callingValues["PortfolioId"] != null)
        {
          var portfolioId = _callingValues["PortfolioId"].ToString();
          var filter = $"portfolio_id = {portfolioId}";

          var models = await _repository.GetComplianceModelsAsync(OwnerId, filter, CancellationToken).ConfigureAwait(false);
          if (models.Any(m => m.Code != model.Code && m.State == "U"))
          {
            return false;
          }
        }

        return true;
      }).WithMessage("A portfolio may only have one model unlocked at a time.");
    }
  }
}

