using AutoMapper;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using SolvasAm.Common.Caching.Abstractions;
using SolvasAm.Common.Extensions;
using SolvasAm.Common.GrpcApi.ResourceNames;
using SolvasAm.Common.Models;
using SolvasFabric.Grpc.Client;
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

namespace SolvasAmCompliance.Modeling.Shared.CacheDataProvider
{
  public class ServiceBasedMapDataProvider<T> : IObjectMapChangeTrackingDataProvider<T> where T : Identity
  {
    protected readonly IServiceProvider ServiceProvider;
    protected readonly ILogger<ServiceBasedMapDataProvider<T>> Logger;
    protected readonly IMapper Mapper;

    public ServiceBasedMapDataProvider(IServiceProvider serviceProvider, ILogger<ServiceBasedMapDataProvider<T>> logger)
    {
      ServiceProvider = serviceProvider;
      Logger = logger;
      Mapper = ServiceProvider.GetRequiredService<IMapper>();
    }

    public virtual async Task<IEnumerable<T>> GetAllAsync(string ownerId, string filter, ResourceParent resourceParent, CancellationToken cancellationToken = default)
    {
      IEnumerable<T> result = default;
      Logger.Debug("Building the object map using ServiceBasedMapDataProvider - {owner}, {type}", ownerId, typeof(T).Name);

      Stopwatch stopwatch = new Stopwatch();
      stopwatch.Start();

      var modelingClient = await ServiceProvider.GetGrpcClientAsync<GrpcApi.V1.ModelingService.ModelingServiceClient>("compliance-modeling", cancellationToken).ConfigureAwait(false);
      filter ??= string.Empty;
      if (typeof(T) == typeof(SolvasAm.Common.Model.Expression.Rule))
      {
        filter += "hydrate =\"Full\"";
        string parent = ResourceName.Format<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(ownerId, parent: resourceParent);
        var ruleResponse = await modelingClient.ListModelExpressionRulesAsync(new SolvasAm.Common.GrpcApi.V1.ListRequest { Parent = parent, Filter = filter }, cancellationToken: cancellationToken);
        result = ruleResponse.ModelExpressionRules.Select(Mapper.Map<T>).ToList();
      }

      // TODO: Add more types that need to be supported for cache.
      stopwatch.Stop();
      Logger.Debug($"Time to build the map with {result?.Count()} objects is {stopwatch.ElapsedMilliseconds} ms");
      return result;
    }

    public virtual async Task<T> GetByKeyAsync(string ownerId, string key, ResourceParent resourceParent, CancellationToken cancellationToken = default)
    {
      Logger.Debug("Adding an object in the map using ServiceBasedMapDataProvider - {owner}, {type}", ownerId, typeof(T).Name);
      var modelingClient = await ServiceProvider.GetGrpcClientAsync<GrpcApi.V1.ModelingService.ModelingServiceClient>("compliance-modeling", cancellationToken).ConfigureAwait(false);
      if (typeof(T) == typeof(SolvasAm.Common.Model.Expression.Rule))
      {
        string name = ResourceName.Format<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(ownerId, key, resourceParent);
        var rule = await modelingClient.GetModelExpressionRuleAsync(new SolvasAm.Common.GrpcApi.V1.GetRequest { Name = name, }, cancellationToken: cancellationToken);
        return Mapper.Map<T>(rule);
      }

        // TODO: Add more types that need to be supported for cache.
        return default;
    }

    public async Task<ChangeTracker> GetChangeTrackRecordAsync(string ownerId, ResourceParent resourceParent, CancellationToken cancellationToken = default)
    {
      ChangeTracker result = default;
      GrpcApi.V1.ResourceCollectionStatistics statsResponse = null;
      Logger.Debug("Fetching the changetracker record using ServiceBasedMapDataProvider - {owner}, {type}", ownerId, typeof(T).Name);

      Stopwatch stopwatch = new Stopwatch();
      stopwatch.Start();

      var modelingClient = await ServiceProvider.GetGrpcClientAsync<GrpcApi.V1.ModelingService.ModelingServiceClient>("compliance-modeling", cancellationToken).ConfigureAwait(false);
      if (typeof(T) == typeof(SolvasAm.Common.Model.Expression.Rule))
      {
        string parent = ResourceName.Format<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(ownerId, parent: resourceParent);
        statsResponse = await modelingClient.GetModelExpressionRulesStatisticsAsync(new GrpcApi.V1.ResourceCollectionStatisticsRequest { Parent = parent }, cancellationToken: cancellationToken);
      }

        // TODO: Add more types that need to be supported for cache.

        if (statsResponse != null)
      {
        result = new ChangeTracker
        {
          RecordCount = (int)statsResponse.Count,
          LatestEtag = statsResponse.LatestEtag != null ? Convert.FromBase64String(statsResponse.LatestEtag) : null
        };
      }

      stopwatch.Stop();
      Logger.Debug($"Time to fetch the change tracker record is {stopwatch.ElapsedMilliseconds} ms");
      return result;
    }
  }
}

using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using Solvas.Owner.Client.SqlServer;
using Solvas.Owner.Client.SqlServer.Abstractions;
using SolvasAm.Common.Extensions;
using SolvasAm.Common.GrpcApi.ResourceNames;
using SolvasAm.Common.Models;
using SolvasFabric.Linq.Extensions.Filter;
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

namespace SolvasAmCompliance.Modeling.Shared.CacheDataProvider
{
  public class WassupsBasedMapDataProvider<T, U> : ServiceBasedMapDataProvider<T> where T : Identity where U : DbContext
  {
    private readonly IFilterTranslator _filterTranslator;
    private readonly IDatabaseRouter _databaseRouter;

    public WassupsBasedMapDataProvider(IServiceProvider serviceProvider, ILogger<WassupsBasedMapDataProvider<T, U>> logger, IFilterTranslator filterTranslator, IDatabaseRouter databaseRouter) : base(serviceProvider, logger)
    {
      _filterTranslator = filterTranslator;
      _databaseRouter = databaseRouter;
    }

    public override async Task<IEnumerable<T>> GetAllAsync(string ownerId, string filter, ResourceParent resourceParent, CancellationToken cancellationToken = default)
    {
      Logger.Debug("Building the object map using WassupsBasedMapDataProvider - {owner}, {type}", ownerId, typeof(T).Name);
      Stopwatch stopwatch = new Stopwatch();
      stopwatch.Start();

      List<T> items = null;
      // Make sure we instantiate in scope to avoid memory leaks (see note in Startup.cs).
      var contextFactory = ServiceProvider.GetRequiredService<IAsyncDbContextFactory<U>>();
      using var contextScope = _databaseRouter.CreateScope(ownerId);
      using var context = await contextFactory.CreateDbContextAsync(cancellationToken).ConfigureAwait(false);

      var executionStrategy = context.Database.CreateExecutionStrategy();

      var filterExpression = _filterTranslator.Parse<T>(filter);
      await executionStrategy.ExecuteAsync(async (_) =>
      {
        items = await context.Set<T>().Where(filterExpression)
               .ToListAsync(cancellationToken)
               .ConfigureAwait(false);
      },
      cancellationToken).ConfigureAwait(false);

      stopwatch.Stop();
      Logger.Debug($"Time to build the map with {items.Count} objects is {stopwatch.ElapsedMilliseconds} ms");
      return items;
    }
  }
}

using Fabric.Wassups.Extensions;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using Solvas.Owner.Client.SqlServer.Abstractions;
using SolvasAm.Common.Extensions;
using SolvasFabric.EntityFramework.Extensions;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.RegularExpressions;
using System.Threading;
using System.Threading.Tasks;


namespace SolvasAmCompliance.Modeling.Shared
{

  public class WassupModelingConsumerHandler<TDbContext> : WassupsConsumerHandlerBase<TDbContext>
      where TDbContext : DbContext, IModelingDbContext, IWassupConsumerEventOffsetDbContext
  {

    private readonly Regex _rx = new Regex("^Id$|CreatedBy|CreatedAt");

    public WassupModelingConsumerHandler(IServiceProvider serviceProvider, IDatabaseRouter databaseRouter, ILogger<WassupModelingConsumerHandler<TDbContext>> logger) : base(serviceProvider, databaseRouter, logger)
    {
    }

    protected override async Task ResetModelAsync(string wassupServiceName, TDbContext context, CancellationToken cancellationToken)
    {
      var schemaName = context.Templates.EntityType.GetSchema();

      var tableNames = new List<string>()
      {
        context.Templates.EntityType.GetTableName(),
        context.TemplateParameters.EntityType.GetTableName(),
        context.TemplateParameterPurposes.EntityType.GetTableName(),
        context.TemplateParameterDataTypes.EntityType.GetTableName(),
        context.TemplateParameterValueTypes.EntityType.GetTableName(),
        context.TemplatePortfolios.EntityType.GetTableName(),
        context.CustomSuccessCriteria.EntityType.GetTableName(),
        context.EligibilityCriteria.EntityType.GetTableName()
      };

      foreach (var tableName in tableNames)
      {
        await context.Database.ExecuteSqlRawAsync($"delete from [{schemaName}].[{tableName}]", cancellationToken).ConfigureAwait(false);
      }

    }

    private async Task<T> GetIdentityItemByIdAsync<T>(DbSet<T> dbSet, EntityEvent eev, CancellationToken cancellationToken) where T : SolvasAm.Common.Models.Identity
    {
      if (eev.Action == "add" || eev.Action == "delete")
      {
        return null;
      }

      return await dbSet.Where(c => c.Id == Guid.Parse(eev.Properties["Id"].ToString())).FirstOrDefaultAsync(cancellationToken).ConfigureAwait(false);

    }

    protected override async Task ProcessEntityEventAsync(string wassupServiceName, TDbContext context, EntityEvent eev, CancellationToken cancellationToken)
    {
      SolvasAm.Common.Models.Identity existingItem = null;

      switch (eev.Type)
      {

        #region Template

        case nameof(Model.Template.Template):
          existingItem = await GetIdentityItemByIdAsync(context.Templates, eev, cancellationToken).ConfigureAwait(false);
          await ProcessEntityEventAsync(
            context,
            context.Templates,
            eev,
            key => new Model.Template.Template() { Id = Guid.Parse(key["Id"].ToString()) },
            existingItem,
            cancellationToken
          ).ConfigureAwait(false);
          break;

        case nameof(Model.Template.Parameter):
          existingItem = await GetIdentityItemByIdAsync(context.TemplateParameters, eev, cancellationToken).ConfigureAwait(false);
          await ProcessEntityEventAsync(
            context,
            context.TemplateParameters,
            eev,
            key => new Model.Template.Parameter() { Id = Guid.Parse(key["Id"].ToString()) },
            existingItem,
            cancellationToken
          ).ConfigureAwait(false);
          break;

        case nameof(Model.Template.ParameterPurpose):
          existingItem = await GetIdentityItemByIdAsync(context.TemplateParameters, eev, cancellationToken).ConfigureAwait(false);
          await ProcessEntityEventAsync(
            context,
            context.TemplateParameterPurposes,
            eev,
            key => new Model.Template.ParameterPurpose() { Id = Guid.Parse(key["Id"].ToString()) },
            existingItem,
            cancellationToken
          ).ConfigureAwait(false);
          break;

        case nameof(Model.Template.ParameterDataType):
          existingItem = await GetIdentityItemByIdAsync(context.TemplateParameterDataTypes, eev, cancellationToken).ConfigureAwait(false);
          await ProcessEntityEventAsync(
            context,
            context.TemplateParameterDataTypes,
            eev,
            key => new Model.Template.ParameterDataType() { Id = Guid.Parse(key["Id"].ToString()) },
            existingItem,
            cancellationToken
          ).ConfigureAwait(false);
          break;

        case nameof(Model.Template.ParameterValueType):
          existingItem = await GetIdentityItemByIdAsync(context.TemplateParameterValueTypes, eev, cancellationToken).ConfigureAwait(false);
          await ProcessEntityEventAsync(
            context,
            context.TemplateParameterValueTypes,
            eev,
            key => new Model.Template.ParameterValueType() { Id = Guid.Parse(key["Id"].ToString()) },
            existingItem,
            cancellationToken
          ).ConfigureAwait(false);
          break;

        case nameof(Model.Template.TemplatePortfolio):
          existingItem = await GetIdentityItemByIdAsync(context.TemplatePortfolios, eev, cancellationToken).ConfigureAwait(false);
          await ProcessEntityEventAsync(
            context,
            context.TemplatePortfolios,
            eev,
            key => new Model.Template.TemplatePortfolio() { Id = Guid.Parse(key["Id"].ToString()) },
            existingItem,
            cancellationToken
          ).ConfigureAwait(false);
          break;

        case nameof(Model.Template.CustomSuccessCriteria):
          existingItem = await GetIdentityItemByIdAsync(context.CustomSuccessCriteria, eev, cancellationToken).ConfigureAwait(false);
          await ProcessEntityEventAsync(
            context,
            context.CustomSuccessCriteria,
            eev,
            key => new Model.Template.CustomSuccessCriteria() { Id = Guid.Parse(key["Id"].ToString()) },
            existingItem,
            cancellationToken
          ).ConfigureAwait(false);
          break;

        case nameof(Model.Template.EligibilityCriteria):
          existingItem = await GetIdentityItemByIdAsync(context.EligibilityCriteria, eev, cancellationToken).ConfigureAwait(false);
          await ProcessEntityEventAsync(
            context,
            context.EligibilityCriteria,
            eev,
            key => new Model.Template.EligibilityCriteria() { Id = Guid.Parse(key["Id"].ToString()) },
            existingItem,
            cancellationToken
          ).ConfigureAwait(false);
          break;

          #endregion

      }
    }

    protected async Task ProcessEntityEventAsync<TEntity>(TDbContext context, DbSet<TEntity> dbSet, EntityEvent eev, Func<Dictionary<string, object>, TEntity> createByKey, SolvasAm.Common.Models.Identity existingItem, CancellationToken cancellationToken) where TEntity : SolvasAm.Common.Models.Identity, new()
    {
      switch (eev.Action)
      {
        case "add":
          {
            TEntity entity3 = JsonConvert.DeserializeObject<TEntity>(JsonConvert.SerializeObject(eev.Properties));
            await dbSet.AddAsync(entity3, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
            var typeName = typeof(TEntity).Name;

            if (typeName == typeof(Model.Template.Parameter).Name || typeName == typeof(Model.Template.TemplatePortfolio).Name || typeName == typeof(Model.Template.CustomSuccessCriteria).Name)
            {
              context.Entry(entity3).Property("TemplateId").CurrentValue = System.Guid.Parse(eev.Properties["TemplateId"].ToString());
            }

            if (typeName == typeof(Model.Template.ParameterPurpose).Name)
            {
              context.Entry(entity3).Property("ParameterId").CurrentValue = System.Guid.Parse(eev.Properties["ParameterId"].ToString());
            }

            break;
          }
        case "update":
          {
            TEntity entity = JsonConvert.DeserializeObject<TEntity>(JsonConvert.SerializeObject(eev.Properties));
            foreach (var property in eev.Properties.Where(p => !_rx.IsMatch(p.Key)).ToList())
            {
              existingItem.SetPropertyValue(property.Key, entity.GetPropertyValue(property.Key));
            }

            TEntity entity2 = existingItem as TEntity;
            dbSet.Update(entity2);
            break;
          }
        case "delete":
          {
            var item = await dbSet.Where(c => c.Id == Guid.Parse(eev.Key["Id"].ToString()))
                                .FirstOrDefaultAsync(cancellationToken)
                                 .ConfigureAwait(false);
            dbSet.Attach(item);
            dbSet.Remove(item);
            break;
          }
      }
    }

  }
}

