    protected override async Task ProcessEntityEventAsync(EntityEvent eev, object cache, CancellationToken cancellationToken)
    {
      switch (eev.Type)
      {
        case nameof(Model.Template.Template):
          await UpdateMapAsync<Model.Template.Template>(
         eev,
         cache,
         cancellationToken
       ).ConfigureAwait(false);
