using FluentValidation;
using SolvasAm.Common.Database.Abstractions;
using SolvasAm.Common.Validators;

namespace SolvasAmCompliance.Modeling.Core.Validators.Test
{
  public class EligibilityCriteriaValidator : IdentityValidator<Core.Model.Test.EligibilityCriteria>
  {
    private readonly IModelingRepository _repository;

    public EligibilityCriteriaValidator(IModelingRepository repository, IValidationModeProvider modeProvider, IRepositoryItems itemsProvider) : base(modeProvider, itemsProvider, true)
    {
      _repository = repository;

      RuleFor(e => e.Type).NotEmpty().MaximumLength(1);
      RuleFor(e => e.Name).MaximumLength(255);
      RuleFor(e => e.Description).MaximumLength(1024);
      RuleFor(e => e.DocumentReference).MaximumLength(255);
      RuleFor(e => e.Comments).MaximumLength(1024);
      RuleFor(e => e.EffectiveBeginDate).NotEmpty();
      RuleFor(e => e).Custom((eligibilityCriteria, context) =>
      {
        if (eligibilityCriteria.EffectiveEndDate?.Date.CompareTo(eligibilityCriteria.EffectiveBeginDate?.Date) < 0)
        {
          context.AddFailure("EffectiveEndDate", "End date must be greater than or equal to Begin date");
        }
      });
      RuleFor(e => e.ReportReference).MaximumLength(255);

      RuleFor(s => s.Type).MustAsync(async (type, cancelToken) =>
      {
        if (_validationMode != ValidationMode.Full)
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, ComplianceEnum.EligibilityCriteria.TestType, cancelToken).ConfigureAwait(false);
        return lookupItems.Contains(type);
      }).WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "Test.EligibilityCriteria.Type must be of an existing type");
    }
  }
}

using FluentValidation;
using SolvasAm.Common.Database.Abstractions;
using SolvasAm.Common.Validators;
using SolvasAmCompliance.Modeling.Core.Model.Rating;
using System.Collections.Generic;
using System.Linq;

namespace SolvasAmCompliance.Modeling.Core.Validators.Rating
{
  public class RuleValidator : IdentityValidator<Rule>
  {
    private readonly IModelingRepository _repository;

    private List<string> outlookPreferenceDerivedType = new List<string> { "IR" };
    private List<string> designationDerivedAndRuleType = new List<string> { "IR", "ISR", "OSR", "OR", "GAR" };
    private List<string> referenceSecurityLevelDerivedType = new List<string> { "OSR" };
    private List<string> referenceIssuerRatingTypeDerivedType = new List<string> { "ISR", "OR", "GAR" };
    private List<string> notIncludeRatingType = new List<string> { "FIXD" };
    private List<string> multipleRatingCalcMethodDerivedType = new List<string> { "OSR" };
    private List<string> multipleRatingRoundingMethodDerivedType = new List<string> { "OSR" };

    public RuleValidator(IModelingRepository repository, IValidationModeProvider modeProvider, IRepositoryItems itemsProvider) : base(modeProvider, itemsProvider, true)
    {
      _repository = repository;

      RuleFor(r => r.Description).NotEmpty().MaximumLength(100);
      RuleFor(r => r.RuleType).NotEmpty().MaximumLength(4);
      RuleFor(r => r.Priority).NotEmpty().GreaterThanOrEqualTo(1).LessThanOrEqualTo(50);
      RuleFor(r => r.ReferenceRatingType).MaximumLength(4);
      RuleFor(r => r.ReferenceSecurityLevel).MaximumLength(100);
      RuleFor(r => r.ReferenceRatingAgency).MaximumLength(100);
      RuleFor(r => r.ReferenceIssuerRatingType).MaximumLength(4);
      RuleFor(r => r.Rating).MaximumLength(4);
      RuleFor(r => r.ReferenceRatingMinimum).MaximumLength(4);
      RuleFor(r => r.ReferenceRatingMaximum).MaximumLength(4);
      RuleFor(r => r.ReferenceRatingAdjustment).LessThanOrEqualTo(3).GreaterThanOrEqualTo(-9);
      RuleFor(r => r.ReferenceRatingAdjustmentMinimum).MaximumLength(4);
      RuleFor(r => r.ReferenceRatingAdjustmentMaximum).MaximumLength(4);
      RuleFor(r => r.ReferenceRatingDowngradeAdjustment).GreaterThanOrEqualTo(-3).LessThanOrEqualTo(0);
      RuleFor(r => r.ReferenceRatingUpgradeAdjustment).GreaterThanOrEqualTo(0).LessThanOrEqualTo(3);
      RuleFor(r => r.MultipleRatingCalculationMethod).MaximumLength(4);
      RuleFor(r => r.MultipleRatingRoundingMethod).MaximumLength(4);
      RuleFor(r => r.ApplicabilityExpressionIdClassic);
      RuleFor(r => r.Comments).MaximumLength(255);
      RuleFor(r => r.ReferenceRatingNegativeOutlookAdjustment).GreaterThanOrEqualTo(-3).LessThanOrEqualTo(0);
      RuleFor(r => r.ReferenceRatingPositiveOutlookAdjustment).GreaterThanOrEqualTo(0).LessThanOrEqualTo(3);
      RuleFor(r => r.Designation).NotEmpty().MaximumLength(100);
      RuleFor(r => r.OutlookPreference).NotEmpty().MaximumLength(100);
      RuleFor(r => r.ApplicabilityExpression);

      RuleFor(r => r.ReferenceRatingType).MustAsync(async (referenceRatingType, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic)
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, "REF_RATING_TYPE", CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(referenceRatingType?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("ReferenceRatingType").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ReferenceRatingType must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || !referenceSecurityLevelDerivedType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, "SECURITY_LEVEL", CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.ReferenceSecurityLevel?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("ReferenceSecurityLevel").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ReferenceSecurityLevel must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || notIncludeRatingType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, ComplianceEnum.RatingScenario.RatingAgency, CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.ReferenceRatingAgency?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("ReferenceRatingAgency").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ReferenceRatingAgency must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, cancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || !designationDerivedAndRuleType.Contains(ratingRule.ReferenceRatingType))
          return true;

        if (string.IsNullOrEmpty(OwnerId))
          return false;

        var lookupItems = await _repository.GetLookupCodes(OwnerId, "RATING_RULE_TYPE", cancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.RuleType?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("RuleType").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
      ? "Owner information not available in the validator context"
      : "RuleType must be of existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || !referenceIssuerRatingTypeDerivedType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, "ISSUER_RATING_TYPE", CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.ReferenceIssuerRatingType?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("ReferenceIssuerRatingType").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ReferenceIssuerRatingType must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || notIncludeRatingType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupType = SetApplicableLookupType(ratingRule.ReferenceRatingAgency);
        var lookupItems = await _repository.GetLookupCodes(OwnerId, lookupType, CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.ReferenceRatingMinimum?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("ReferenceRatingMin").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ReferenceRatingMin must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || notIncludeRatingType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupType = SetApplicableLookupType(ratingRule.ReferenceRatingAgency);
        var lookupItems = await _repository.GetLookupCodes(OwnerId, lookupType, CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.ReferenceRatingMaximum?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("ReferenceRatingMax").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ReferenceRatingMax must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || notIncludeRatingType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupType = SetApplicableLookupType(ratingRule.ReferenceRatingAgency);
        var lookupItems = await _repository.GetLookupCodes(OwnerId, lookupType, CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.ReferenceRatingAdjustmentMaximum?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("ReferenceRatingAdjMax").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ReferenceRatingAdjMax must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || notIncludeRatingType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupType = SetApplicableLookupType(ratingRule.ReferenceRatingAgency);
        var lookupItems = await _repository.GetLookupCodes(OwnerId, lookupType, CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.ReferenceRatingAdjustmentMinimum?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("ReferenceRatingAdjMin").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ReferenceRatingAdjMin must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || !multipleRatingCalcMethodDerivedType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, "RATING_RULE_CALC", CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.MultipleRatingCalculationMethod?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("MultipleRatingCalcMethod").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "MultipleRatingCalcMethod must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || !multipleRatingRoundingMethodDerivedType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, "RATING_RULE_ROUND", CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.MultipleRatingRoundingMethod?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("MultipleRatingRoundingMethod").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "MultipleRatingRoundingMethod must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || !outlookPreferenceDerivedType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, "OUTLOOK_PREFERENCE", CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.OutlookPreference?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("OutlookPreference").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "OutlookPreference must be of an existing type");

      RuleFor(r => r).MustAsync(async (ratingRule, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || !designationDerivedAndRuleType.Contains(ratingRule.ReferenceRatingType))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, "DERIVATION_DESIGNATION", CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ratingRule.Designation?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithName("Designation").WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "Designation must be of an existing type");
    }

    public string SetApplicableLookupType(string ratingAgency)
    {
      switch (ratingAgency?.Trim()?.ToUpper())
      {
        case "DBRS":
          return "DBRS_RATING";
        case "FR":
          return "FITCH_RATING";
        case "KBRA":
          return "KBRA_RATING";
        case "MR":
          return "MOODY_RATING";
        case "SPR":
          return "SP_RATING";
        default:
          return "DBRS_RATING";
      }
    }
  }
