using SolvasFabricConfiguration = SolvasFabric.Service.Common.Configuration;

namespace SolvasAmCompliance.Modeling.Grpc.Internal
{
  public class Startup : IStartup
  {
    public IConfiguration Configuration { get; }

    public Startup()
    {
      Configuration = BuildConfiguration();
    }

    // This method gets called by the runtime. Use this method to add services to the Dependency Injection container.
    public void ConfigureServices(IServiceCollection serviceCollection)
    {
      serviceCollection
        // Add automatic generation of Wassup events based on Entity Framework change detection.
        .AddSolvasFabricEntityFrameworkWassup(Configuration, noTrackingTypes: new Type[]
        {
          // Remove data-seed-history-update noise from our published Wassup event streams.
          typeof(SolvasAm.Common.Models.DataSeedRecord),
          typeof(SolvasAm.Common.Models.LookupType),
          typeof(SolvasAm.Common.Models.LookupItem),
          typeof(SolvasAm.Common.Models.LookupItemGroup),
          typeof(SolvasAm.Common.Models.LookupCompositionLink),
          typeof(SolvasAm.Common.Model.ReferenceData.DataType),
          typeof(SolvasAm.Common.Model.ReferenceData.DataFormat),
        })

        // Add Solvas Fabric host infrastructure.
        .AddSolvasFabricServiceHost(Configuration, new ServiceHostOptions { EnableOidc = true })
        // Add Solvas Fabric client infrastructure.
        .AddSolvasFabricServiceClient(Configuration, new ServiceClientOptions { EnableOidc = true })
        // Add distributed locking manager.
        .AddDistributedLockingInfrastructure(Configuration)
        .AddDistributedLockingKeyProvider(Configuration)
        // wassups integration
        .AddSingleton<IWassupEventScopeDetector, ModelingWassupEventScopeDetector>()
        .AddSingleton<IWassupEventCollector, SolvasAm.Common.Wassups.SolvasAmWassupsEventCollector>()
        // Add the wassups consumer hosting service to manage consumer lifecycle
        .AddFabricWassupsConsumerHostedService(Configuration)
        // Override the default Wassup offset proivider.
        // Note that this must be called after AddFabricWassupsConsumerHostedService.
        .AddSingleton<IWassupsEventOffsetProvider, WassupsConsumerEventOffsetProvider<ModelingDbContext>>()
        // Register domain data Wassup consumer.
        .AddWassupsAsyncConsumer<WassupDomainDataConsumerHandler<ModelingDbContext>>("solvasam-domaindata-wassups", "compliance-modeling", new string[] { })
        // Register our service API with the gRPC host.
        .AddApiClient<Fabric.Wassups.GrpcApi.V1.WassupsService.WassupsServiceClient>()
        // Register the client stub which will give us access to services which implement data seed registries.
        .AddApiClient<SolvasAm.DomainData.GrpcApi.V1.DomainDataService.DomainDataServiceClient>()
        .AddApiClient<SolvasAmPortfolio.Organizations.GrpcApi.V1.OrganizationsService.OrganizationsServiceClient>()
        //Add a client to our own service. This is for the RuleCache to work.
        .AddApiClient<ModelingService.ModelingServiceClient>()
        .AddHostApi<ModelingServiceImpl>(ModelingService.BindService, ModelingService.Descriptor)
       // Register automapper profiles.
        .AddSingleton<AutoMapper.IConfigurationProvider>(_ => new MapperConfiguration(cfg =>
        {
          cfg.AddProfile<GrpcToModelAutoMapperProfile>();
          cfg.AddProfile<ExportAutoMapperProfile>();
          cfg.AddProfile<DomainDataSharedModelProfile>();
          cfg.AddProfile<OrganizationsSharedModelProfile>();
        }))
        // Register automapper.
        .AddTransient<IMapper>(services => new Mapper(services.GetRequiredService<AutoMapper.IConfigurationProvider>()))
        .AddSingleton<SolvasAm.Common.Validators.IValidationModeProvider, SolvasAm.Common.Validators.ConfigBasedValidationModeProvider>()
        // Register our validators.
        .AddValidatorsFromAssemblyContaining<Core.Validators.ComplianceModel.ModelValidator>(ServiceLifetime.Transient)
        .AddValidatorsFromAssemblyContaining<SolvasAm.Common.Validators.Expression.RuleValidator>(ServiceLifetime.Transient)
        //solvas-owner integration
        .AddApiClient<Solvas.Owner.GrpcApi.V1.OwnerService.OwnerServiceClient>()
        .AddAsyncObservableWassupProducerDbContextFactory<ModelingDbContext>(Configuration, "compliance-modeling")
        .AddSingleton<DbInitializer>();

      // Add translator to translate order expressions to chained EF IOrderedQueryables.
      SolvasFabric.Linq.Extensions.ServiceCollectionExtensions.AddEntityFrameworkOrderTranslator(serviceCollection);

      // In a normal Flaming Volcano project, we would set the options action directly here.
      // When using the router, use the options action provided by the router to enable dynamic routing.      
      serviceCollection
        .AddEntityFrameworkFilterTranslator()
        .AddSingleton<IMemberNameResolver, AutoMapperBasedProtoMemberNameResolver>()
        .AddSingleton<ModelingRepository>()
        .AddSingleton<IModelingRepository>(svcProvider => svcProvider.GetRequiredService<ModelingRepository>())
        .AddSingleton<IRepositoryItems>(svcProvider => svcProvider.GetRequiredService<ModelingRepository>())
        // Register the standard data seed registry repository implementation.
        .AddEntityFrameworkDataSeedRegistryRepository<ModelingDbContext>()

        .AddDomainDataLookupSnapshotCache(Configuration)
        .AddDomainDataSnapshotCache<SolvasAm.DomainData.Shared.Model.DataDictionary.Field>(Configuration)
        .AddDomainDataSnapshotCache<SolvasAm.DomainData.Shared.Model.ReferenceData.FunctionDefinition>(Configuration)
        .AddModelingSnapshotCache<SolvasAm.Common.Model.Expression.Rule>(Configuration)
        .AddPortfolioOrganizationsCache<SolvasAmPortfolio.Organizations.Shared.Model.Portfolio.Portfolio.Portfolio>(Configuration)
        .AddServiceInterceptors<ModelingServiceImpl>();

      serviceCollection.AddSprocContext<ModelingSprocContext>();
      serviceCollection.Configure<FeatureFlags>(Configuration.GetSection("featureFlags"));
    }

    // This method gets called by the runtime. Use this method to configure the services.
    public void Configure(IServiceProvider serviceProvider)
    {
      // Set up logging and OIDC self-registration.
      serviceProvider
        .ConfigureSolvasFabricServiceHost<Startup>()
        .ConfigureSolvasFabricServiceClient();
    }

