namespace SolvasAm.Common.Interceptors
{
  public enum ApiRequestType
  {
    NONE = 0,
    GET,
    LIST,
    CREATE,
    UPDATE,
    DELETE,
    COPY,
    CUSTOM
  }

  [AttributeUsage(AttributeTargets.Method)]
  public class ValidateRequestAttribute : Attribute
  {
    public ValidateRequestAttribute(ApiRequestType apiRequestType)
    {
      ApiRequestType = apiRequestType;
    }

    public ApiRequestType ApiRequestType { get; }
    public string ValidationProperty { get; set; }
  }

  public class ValidateRequestInterceptor : InterceptorWithApiTypeReflection
  {
    private readonly ConcurrentDictionary<Type, (bool, ValidateRequestAttribute)> _validatorMap;

    public ValidateRequestInterceptor()
    {
      _validatorMap = new ConcurrentDictionary<Type, (bool, ValidateRequestAttribute)>();
    }

    public override async Task<TResponse> UnaryServerHandler<TRequest, TResponse>(TRequest request, ServerCallContext context, UnaryServerMethod<TRequest, TResponse> continuation)
    {
      if (request is IMessage requestMessage && RequiresValidation(context, continuation.Method, out ValidateRequestAttribute attr))
      {
        switch (attr.ApiRequestType)
        {
          case ApiRequestType.LIST:
            {
              // List request must always have a 'parent' field at 1.
              var fieldDescriptor = requestMessage.Descriptor.FindFieldByName("parent");
              if (fieldDescriptor == null || string.IsNullOrEmpty(fieldDescriptor.Accessor.GetValue(requestMessage)?.ToString()))
              {
                RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Parent is required.");
              }
              fieldDescriptor = requestMessage.Descriptor.FindFieldByName("page_size");
              if (fieldDescriptor == null || Convert.ToInt32(fieldDescriptor.Accessor.GetValue(requestMessage)?.ToString()) < 0)
              {
                RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Invalid page size.");
              }
            }
            break;
          case ApiRequestType.CREATE:
            {
              // Create request must always have a 'parent' field at 1 and resource at 2.
              var fieldDescriptor = requestMessage.Descriptor.FindFieldByName("parent");
              if (fieldDescriptor == null || string.IsNullOrEmpty(fieldDescriptor.Accessor.GetValue(requestMessage)?.ToString()))
              {
                RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Parent is required.");
              }
              fieldDescriptor = requestMessage.Descriptor.FindFieldByNumber(2);
              if (fieldDescriptor == null || fieldDescriptor.Accessor.GetValue(requestMessage) == null)
              {
                RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Resource is required.");
              }
            }
            break;
          case ApiRequestType.UPDATE:
            {
              //The updateRequest message should always have resource as the first field.
              // The resource in the request message should always have the first field as the name (aka resource name)
              var fieldDescriptor = requestMessage.Descriptor.FindFieldByNumber(1);
              if (fieldDescriptor == null || fieldDescriptor.Accessor.GetValue(requestMessage) == null)
                RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Resource is required.");

              IMessage resource = fieldDescriptor.Accessor.GetValue(requestMessage) as IMessage;
              var nameFieldDescriptor = fieldDescriptor.MessageType.FindFieldByName("name");
              if (nameFieldDescriptor == null || string.IsNullOrEmpty(nameFieldDescriptor.Accessor.GetValue(resource)?.ToString()))
              {
                RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Resource name is required.");
              }

              var eTagFieldDescriptor = fieldDescriptor.MessageType.FindFieldByName("etag");
              if (eTagFieldDescriptor == null || string.IsNullOrEmpty(eTagFieldDescriptor.Accessor.GetValue(resource)?.ToString()))
              {
                RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "ETag is required.");
              }
            }
            break;
          case ApiRequestType.DELETE:
          case ApiRequestType.GET:
            {
              //get request must always have a name field at 1.
              var nameFieldDescriptor = requestMessage.Descriptor.FindFieldByName("name");
              if (nameFieldDescriptor == null || string.IsNullOrEmpty(nameFieldDescriptor.Accessor.GetValue(requestMessage)?.ToString()))
              {
                RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Resource name is required.");
              }
            }
            break;
          case ApiRequestType.COPY:
            {
              // Copy request must always have a 'parent' field at 1 and an array of strings at 2.
              var fieldDescriptor = requestMessage.Descriptor.FindFieldByName("parent");
              if (fieldDescriptor == null || string.IsNullOrEmpty(fieldDescriptor.Accessor.GetValue(requestMessage)?.ToString()))
              {
                RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Parent is required.");
              }
              fieldDescriptor = requestMessage.Descriptor.FindFieldByNumber(2);
              if (fieldDescriptor == null || fieldDescriptor.Accessor.GetValue(requestMessage) == null || !fieldDescriptor.Accessor.GetValue(requestMessage).GetType().IsGenericType
                  || !fieldDescriptor.Accessor.GetValue(requestMessage).GetType().Name.Contains("RepeatedField") || (fieldDescriptor.Accessor.GetValue(requestMessage).GetType().GenericTypeArguments[0] != typeof(string)))
              {
                RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Names is required.");
              }
            }
            break;
          case ApiRequestType.CUSTOM:
            {
              if (attr.ValidationProperty != null)
              {
                var nameFieldDescriptor = requestMessage.Descriptor.FindFieldByName(attr.ValidationProperty.Underscore());
                if (nameFieldDescriptor == null || nameFieldDescriptor.Accessor.GetValue(requestMessage) == null)
                {
                  RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, $"{attr.ValidationProperty} is required.");
                }
              }
            }
            break;
        }
      }

      try
      {
        return await base.UnaryServerHandler(request, context, continuation).ConfigureAwait(false);
      }
      catch (Grpc.Core.RpcException)
      {
        throw;
      }
      catch (Exception ex)
      {
        RpcExceptionHelper.ThrowWithStatus(StatusCode.Internal, ex.Message);
      }

      return default;
    }

    private bool RequiresValidation(ServerCallContext context, MethodInfo method, out ValidateRequestAttribute attr)
    {
      // We cache the attribute information in a concurrent dictionary, because Attribute.GetCustomAttribute
      // performs reflection against the assembly metadata and can get pricey.
      if (!_validatorMap.TryGetValue(method.DeclaringType, out (bool validate, ValidateRequestAttribute attr) mapValue))
      {
        var attributes = GetCustomAttributes<ValidateRequestAttribute>(context).ToList();
        mapValue.validate = attributes.Count > 0;
        if (mapValue.validate)
        {
          mapValue.attr = attributes[0];
        }
        _validatorMap.TryAdd(method.DeclaringType, mapValue);
      }
      attr = mapValue.attr;
      return mapValue.validate;
    }
  }
