using FluentValidation;
using FluentValidation.Results;
using SolvasAm.Common.Database.Abstractions;
using SolvasAm.Common.Models;
using SolvasAm.Common.Models.Exceptions;
using System;
using System.Collections.Generic;

namespace SolvasAm.Common.Validators
{

  public class IdentityValidator<T> : AuditValidator<T> where T : Identity
  {
    protected IRepositoryItems ItemsProvider { get; }
    protected ValidationMode _validationMode;
    protected Dictionary<string, object> _callingValues = new Dictionary<string, object>();
    protected string OwnerId { get; private set; }

    protected override bool PreValidate(ValidationContext<T> context, ValidationResult result)
    {
      if (context.RootContextData.ContainsKey("CallingValues"))
      {
        _callingValues = (Dictionary<string, object>)context.RootContextData["CallingValues"];
      }
      if (_callingValues.TryGetValue("ownerId", out object owner))
      {
        OwnerId = owner.ToString();
      }
      return true;
    }

    public IdentityValidator(IValidationModeProvider modeProvider, IRepositoryItems itemsProvider, bool skipDuplicateCodeCheck = false)
    {
      _validationMode = modeProvider.ValidationMode; //comes from config "enableDbValidation" setting
      ItemsProvider = itemsProvider;

      //RuleFor(e => e.Id).NotEmpty(); Disabling this so we can set the Id later on in the create process, in the repo.
      RuleFor(i => i.Code).NotEmpty().MaximumLength(100);

      RuleFor(i => i.Etag).Must((field, etag) => field.Id == Guid.Empty || etag != null).WithMessage("ETag is required.");
      //TODO: A repository cannot be passed in since all the services have different Repository interfaces.
      // Two different approaches can be taken here
      // 1. Expose an IUniqueCodeValidator interface and have all the repositories implement this interface too.
      //      - This interface will have a single method bool ValidateCode(id, code, extraId, cancellationToken)
      //        which will take the Identity id,code, owner etc to check if the code is unique.
      // 2. Convert the existing Repository interface in each service to be a generic one - IRepository<T>.
      //    This is probably not going to happen anytime soon. Easier in repos that use EF. For shim based repos,
      //    this will not work until shim is replaced by EF.

      RuleFor(c => c.Code).MustAsync(async (field, code, cancellationToken) =>
      {
        // IMPORTANT: This flag is used now to skip the code validation for the Shim based models.
        // Since the code to check for duplicate code is based on Generic EF Core logic, they are irrelevant and will fail for the shim
        // based logic. However, once the shim logic is replaced by EF logic for all the models, we can get rid of this flag.
        if (skipDuplicateCodeCheck)
          return true;

        if (string.IsNullOrEmpty(code) || string.Compare(code, "AUTO_ASSIGN", true) == 0)
          return true;

        try
        {
          //unique code extraId for uniqueness
          Guid extraId = Guid.Empty;
          string extraIdPropertyName = null;

          if (_callingValues.ContainsKey("ExtraId"))
          {
            extraId = Guid.Parse(_callingValues["ExtraId"].ToString());
          }

          if (_callingValues.ContainsKey("ExtraIdPropertyName"))
          {
            extraIdPropertyName = _callingValues["ExtraIdPropertyName"].ToString();
          }

          var existingItem = await ItemsProvider.GetItemByCodeAsync<T>(field.Code, extraId, extraIdPropertyName, cancellationToken: cancellationToken).ConfigureAwait(false);
          if (field.Id == Guid.Empty && existingItem != null)
            return false; // if Id is empty, this is a new resource and the name should not be taken

          if (field.Id != Guid.Empty && (existingItem == null || field.Id != existingItem.Id))
            return false; // if update, then the incoming field id should match the one in db if the field_name is coming in

          return true;
        }
        catch (ItemNotFoundException)
        {
          return true;
        }
      }).WithMessage(c =>
      {
        //unique code extraId for uniqueness
        Guid extraId = Guid.Empty;
        string extraIdPropertyName = null;

        if (_callingValues.ContainsKey("ExtraId"))
        {
          extraId = Guid.Parse(_callingValues["ExtraId"].ToString());
        }

        if (_callingValues.ContainsKey("ExtraIdPropertyName"))
        {
          extraIdPropertyName = _callingValues["ExtraIdPropertyName"].ToString();
        }

        return $"Duplicate unique code {c.Code}. Context: {extraIdPropertyName}:{extraId}";
      });


    }

  }
}

using FluentValidation;
using SolvasAm.Common.Database.Abstractions;
using SolvasAm.Common.Validators;
using SolvasAmCompliance.Modeling.Core.Model.PrincipalBalance;
using System.Linq;

namespace SolvasAmCompliance.Modeling.Core.Validators.PrincipalBalance
{
  public class RuleValidator : IdentityValidator<Rule>
  {
    private readonly IModelingRepository _repository;

    public RuleValidator(IModelingRepository repository, IValidationModeProvider modeProvider, IRepositoryItems itemsProvider) : base(modeProvider, itemsProvider, true)
    {
      _repository = repository;

      RuleFor(p => p.GroupIdClassic).NotEmpty();
      RuleFor(p => p.GroupCode).MaximumLength(100);
      RuleFor(p => p.ValueType).MaximumLength(100);
      RuleFor(p => p.Type).MaximumLength(100);
      RuleFor(p => p.Comments).MaximumLength(255);
      RuleFor(p => p.PurchasePriceOption).MaximumLength(100);
      RuleFor(p => p.ParCalculationMethod).MaximumLength(100);
      RuleFor(p => p.ValueDataType).NotEmpty().MaximumLength(100);
      RuleFor(p => p.Priority).NotEmpty();

      RuleFor(c => c.ValueType).MustAsync(async (valueType, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic)
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, ComplianceEnum.PB.ValueType, CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(valueType?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ValueType must be of an existing type");

      RuleFor(c => c.Type).MustAsync(async (ruleType, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic)
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, ComplianceEnum.PB.RuleType, CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(ruleType?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "RuleType must be of an existing type");

      RuleFor(c => c.ParCalculationMethod).MustAsync(async (parCalcMethod, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || string.IsNullOrEmpty(parCalcMethod))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, ComplianceEnum.PB.ParCalcMethod, CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(parCalcMethod?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ParCalculationMethod must be of an existing type");

      RuleFor(c => c.ValueDataType).MustAsync(async (valueDataType, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic)
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, ComplianceEnum.PB.ValueDataType, CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(valueDataType?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "ValueDataType must be of an existing type");

      RuleFor(c => c.PurchasePriceOption).MustAsync(async (purchasePriceOption, CancellationToken) =>
      {
        if (_validationMode == ValidationMode.Basic || string.IsNullOrEmpty(purchasePriceOption))
        {
          return true;
        }
        if (string.IsNullOrEmpty(OwnerId))
        {
          return false;
        }
        var lookupItems = await _repository.GetLookupCodes(OwnerId, ComplianceEnum.PB.PurchasePriceOption, CancellationToken).ConfigureAwait(false);
        return lookupItems.Any(li => li.Equals(purchasePriceOption?.Trim(), System.StringComparison.OrdinalIgnoreCase));
      }).WithMessage(_ => string.IsNullOrEmpty(OwnerId)
          ? "Owner information not available in the validator context"
          : "PurchasePriceOption must be of an existing type");

    }
  }
}

