    public async override Task<ListModelExpressionRulesResponse> ListModelExpressionRules(SolvasAm.Common.GrpcApi.V1.ListRequest request, ServerCallContext context)
    {
      var cachingRequest = context.RequestHeaders.Get("caching_request");
      if (!bool.TryParse(cachingRequest?.Value, out var isCachingRequest))
      {
        isCachingRequest = false;
      }
      var result = new ListModelExpressionRulesResponse();
      var resourceName = ResourceName.Parse<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(request.Parent, false);
      var permissions = await _oidcResourceAuthorizer.GetUserPermissionsAsync(_credentials.CurrentValue.ClientId, context, _logger).ConfigureAwait(false);
      result.UserPermissions = _mapper.Map<SolvasAm.Common.GrpcApi.V1.UserPermissions>(permissions);

      // If the meta_only field is not set or is set to false, fetch the data
      if (!request.MetaOnly.HasValue || !request.MetaOnly.Value)
      {
        // if it's a caching request, do not try against the cache.
        var modelItems = await _repository.GetModelExpressionRulesAsync(resourceName.OwnerId, request.Filter, context.CancellationToken, !isCachingRequest).ConfigureAwait(false);
        var grpcItems = modelItems.MapToProto<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule, SolvasAm.Common.Model.Expression.Rule>(_mapper, request.Parent, false).ToList();

        var hydrateOption = GetHydrateOptionFromFilter<SolvasAm.Common.Model.Expression.Rule>(request);
        await HydrateModelExpressionRuleAsync(grpcItems, resourceName.OwnerId, context.CancellationToken, hydrateOption).ConfigureAwait(false);
        result.ModelExpressionRules.AddRange(grpcItems);
        result.TotalSize = 0; //we don't provide the actual count as the procedure doesn't support paging
      }
      return result;
    }

    [AuthorizeOwner("expression-list.create", NameProperty = "Parent")]
    [ValidateRequest(ApiRequestType.CREATE)]
    public async override Task<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule> CreateModelExpressionRule(CreateModelExpressionRuleRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(request.Parent, false);

      var grpcItem = request.ModelExpressionRule;
      grpcItem.Name = string.Empty;
      grpcItem.Id = string.Empty;

      grpcItem = await grpcItem.AutoAssignUniqueCodeClassic(resourceName.OwnerId, ComplianceEnum.CodeType.ExpressionRule, grpcItem.RuleName, _repository.GetUniqueCodeClassic, grpcPropertyName: nameof(grpcItem.Code), cancellationToken: context.CancellationToken).ConfigureAwait(false);

      try
      {
        var existingItem = await _repository.GetModelExpressionRuleByCodeAsync(resourceName.OwnerId, grpcItem.Code, context.CancellationToken).ConfigureAwait(false);
        RpcExceptionHelper.ThrowWithStatus(StatusCode.InvalidArgument, "Requested code already in use.");
      }
      catch (ItemNotFoundException)
      {
        var callingValues = new Dictionary<string, object>
        {
          {OWNER_ID_LITERAL, resourceName.OwnerId}
        };

        var validator = _serviceProvider.GetRequiredService<IValidator<SolvasAm.Common.Model.Expression.Rule>>();
        var modelItem = await _mapper.MapToModelAndValidate(grpcItem, ApiRequestType.CREATE, validator, callingValues, context.CancellationToken).ConfigureAwait(false);

        return await CreateOrUpdateModelExpressionRuleAsync(
          resourceName,
          modelItem,
          request.OperationConfirmed,
          context
        ).ConfigureAwait(false);
      }

      return default;
    }

    [AuthorizeOwner("expression-list.update", NameProperty = "ModelExpressionRule.Name")]
    [ValidateRequest(ApiRequestType.UPDATE)]
    public async override Task<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule> UpdateModelExpressionRule(UpdateModelExpressionRuleRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(request.ModelExpressionRule.Name);
      var grpcItem = request.ModelExpressionRule;
      grpcItem.Id = resourceName.Id;

      try
      {
        var existingItem = await _repository.GetModelExpressionRuleByIdAsync(resourceName.OwnerId, grpcItem.Id, context.CancellationToken).ConfigureAwait(false);
        var callingValues = new Dictionary<string, object>
        {
          {OWNER_ID_LITERAL, resourceName.OwnerId}
        };

        var modelItem = await UpdateItemClassicAsync(grpcItem, existingItem, resourceName, request.UpdateMask, context, callingValues).ConfigureAwait(false);

        return await CreateOrUpdateModelExpressionRuleAsync(
        resourceName,
        modelItem,
        request.OperationConfirmed,
        context
        ).ConfigureAwait(false);
      }
      catch (ItemNotFoundException)
      {
        RpcExceptionHelper.ThrowWithStatus(StatusCode.NotFound, $"\"{grpcItem.Name}\" not found.");
      }

      return default;
    }

