  public partial class ModelingServiceImpl : ModelingService.ModelingServiceBase
  {
    private const string MODELING_SCHEMA = "[compliance-modeling]";
    private const int DefaultPageSize = 25;
    private const int MaxPageSize = 1000;
    private const string OWNER_ID_LITERAL = "ownerId";

    private enum HydrateOption
    {
      Full,
      Lite,
      None
    }

    // Dependency Injection service provider.
