    // Reference to the ambient state manager.
    private readonly IAmbientStateManager _stateManager;

    private readonly IMapper _mapper;

    private readonly ILogger _logger;

    private readonly IOidcResourceAuthorizer _oidcResourceAuthorizer;

    private readonly IOptionsMonitor<OidcClientCredentials> _credentials;

    private readonly IDatabaseManager _databaseManager;

    private readonly IDataSeedRegistryRepository _dataSeedRegistryRepo;

    private readonly FilterSProcParameterTranslator _sprocTranslator;
    private readonly IOptionsMonitor<FeatureFlags> _featureFlagOptions;

    public ModelingServiceImpl(IServiceProvider serviceProvider, IModelingRepository repository, IDataSeedRegistryRepository dataSeedRegistryRepo, IAmbientStateManager stateManager, ILogger<ModelingServiceImpl> logger, IOidcResourceAuthorizer oidcResourceAuthorizer, IDatabaseManager databaseManager, IOptionsMonitor<OidcClientCredentials> credentials, IOptionsMonitor<FeatureFlags> featureFlagOptions)
    {
      _serviceProvider = serviceProvider;
      _repository = repository;
      _stateManager = stateManager;
      _mapper = _serviceProvider.GetRequiredService<IMapper>();
      _logger = logger;
      _oidcResourceAuthorizer = oidcResourceAuthorizer;
