    }

    static ModelingServiceImpl()
    {
      ResourceNameCollection.Build();
    }

    #region DataSeeding

    /// <summary>
    /// Create a new data seed record if one doesn't exist yet.
    /// </summary>

    [ValidateRequest(ApiRequestType.CREATE)]
    public async override Task<SolvasAm.Common.GrpcApi.V1.DataSeedRecord> CreateDataSeedRecord(SolvasAm.Common.GrpcApi.V1.CreateDataSeedRecordRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<SolvasAm.Common.GrpcApi.V1.DataSeedRecord>(request.Parent, false);

      var grpcItem = request.DataSeedRecord;
      grpcItem.Name = string.Empty; //ignore any id that come in the body of a create request

      using var _ = _databaseManager.CreateScope(resourceName.OwnerId);
      // Check if the record exists and if it does, do nothing.
      var fromDb = await _dataSeedRegistryRepo.GetDataSeedRecordAsync(grpcItem.Id, context.CancellationToken).ConfigureAwait(false);
      if (fromDb != null)
      {
        RpcExceptionHelper.ThrowWithStatus(StatusCode.AlreadyExists, $"Data Seed Record with Id \"{grpcItem.Id}\" already exists.");
      }
      // Convert the gRPC DTO object to a domain model object.
      var modelDataSeedRecord = _mapper.Map<SolvasAm.Common.GrpcApi.V1.DataSeedRecord, SolvasAm.Common.Models.DataSeedRecord>(grpcItem);
      modelDataSeedRecord.RecordedAt = DateTime.UtcNow;

      await _dataSeedRegistryRepo.CreateDataSeedRecordAsync(modelDataSeedRecord, context.CancellationToken).ConfigureAwait(false);
      var result = await _dataSeedRegistryRepo.GetDataSeedRecordAsync(grpcItem.Id, context.CancellationToken).ConfigureAwait(false);
      return _mapper.Map<SolvasAm.Common.Models.DataSeedRecord, SolvasAm.Common.GrpcApi.V1.DataSeedRecord>(result);
    }

    /// <summary>
    /// Verify if a given data seed record exists.
    /// </summary>
    /// <returns></returns>

    [ValidateRequest(ApiRequestType.GET)]
    public override async Task<SolvasAm.Common.GrpcApi.V1.DataSeedRecord> GetDataSeedRecord(SolvasAm.Common.GrpcApi.V1.GetRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<SolvasAm.Common.GrpcApi.V1.DataSeedRecord>(request.Name);
      using var routerScope = _databaseManager.CreateScope(resourceName.OwnerId);
      var dataSeedRecord = await _dataSeedRegistryRepo.GetDataSeedRecordAsync(resourceName.Id, context.CancellationToken).ConfigureAwait(false);
      if (dataSeedRecord == null)
        RpcExceptionHelper.ThrowWithStatus(StatusCode.NotFound, $"\"{request.Name}\" not found.");

      var result = _mapper.Map<SolvasAm.Common.GrpcApi.V1.DataSeedRecord>(dataSeedRecord);
      result.SetPropertyValue("Name", ResourceName.Format<SolvasAm.Common.GrpcApi.V1.DataSeedRecord>(resourceName.OwnerId, resourceName.Id, resourceName.Parent));
      return result;
    }

    #endregion

    #region Common

    // This is just a warpper method to avoid having to pass schema in each call.
    private Task<string> GetUniqueCode(Guid id, Guid extraId, string code, string codeType, CancellationToken cancellationToken = default)
    {
      return _repository.GetUniqueCode(id, extraId, code, codeType, MODELING_SCHEMA, cancellationToken);
    }

    public async override Task<BoolValue> GetDatabaseInitialized(SolvasAm.Common.GrpcApi.V1.DatabaseInitializedRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<SolvasAm.Common.GrpcApi.V1.DatabaseInitializedRequest>(request.Parent, false); //since we don't have a message for DatabaseInitialized itself (it's just a string)
      using var _ = _databaseManager.CreateScope(resourceName.OwnerId);
      var isInitialized = await _repository.IsDatabaseInitializedAsync(context.CancellationToken).ConfigureAwait(false);
      return new BoolValue { Value = isInitialized };
    }

    public async override Task<StringValue> GetUniqueCode(SolvasAm.Common.GrpcApi.V1.UniqueCodeRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<SolvasAm.Common.GrpcApi.V1.UniqueCodeRequest>(request.Parent, false); //since we don't have a message for UniqueCode itself (it's just a string), use the SolvasAm.Common.GrpcApi.V1.UniqueCodeRequest here as the type <T>
      //var id = SolvasAmHelper.ParseValue<Guid>(request.Id, true);
      //var extraId = SolvasAmHelper.ParseValue<Guid>(request.ExtraId, true);

      var extraIdClassic = request.ExtraId;
      if (!string.IsNullOrEmpty(request.ExtraId))
      {
        try
        {
          var portfolio = await _repository.GetPortfolioByIdAsync(resourceName.OwnerId, request.ExtraId, context.CancellationToken).ConfigureAwait(false);
          extraIdClassic = portfolio.Lid.ToString();
        }

        catch (ItemNotFoundException)
        {
          extraIdClassic = request.ExtraId;
        }

      }

      var code = request.Code;
      var uniqueCode = "";
      using var _ = _databaseManager.CreateScope(resourceName.OwnerId);
      if (ComplianceEnum.CodeType.TemplateCodeTypes.Contains(request.CodeType))
      {
        var id = SolvasAmHelper.ParseValue<Guid>(request.Id, true);
        var extraId = SolvasAmHelper.ParseValue<Guid>(request.ExtraId, true);

        if (string.IsNullOrEmpty(code))
        {
          code = SolvasAmHelper.GetSwappedCode(request.StartingValue);
        }
        uniqueCode = await GetUniqueCode(id, extraId, code, request.CodeType, context.CancellationToken).ConfigureAwait(false);
      }
      else
      {
        if (string.IsNullOrEmpty(code))
        {
          //code = SolvasAmHelper.GetSwappedCode(request.StartingValue);

          //since we are using the shim, just pass in the starting value which will go all the way to the sproc.
          code = request.StartingValue;
        }
        uniqueCode = await _repository.GetUniqueCodeClassic(resourceName.OwnerId, request.Id, extraIdClassic, code, request.CodeType, null, context.CancellationToken).ConfigureAwait(false);
      }
      return new StringValue() { Value = uniqueCode };
    }

    private async Task<Google.Protobuf.WellKnownTypes.Int32Value> CountAsync<T, U>(SolvasAm.Common.GrpcApi.V1.CountRequest request, ServerCallContext context) where T : class, Google.Protobuf.IMessage<T> where U : Identity
    {
      var resourceName = ResourceName.Parse<T>(request.Parent, false);
      using var _ = _databaseManager.CreateScope(resourceName.OwnerId);
      var count = await _repository.GetCountAsync<U>(request.Filter, context.CancellationToken).ConfigureAwait(false);

      return new Int32Value() { Value = count };
    }

    private async Task<T> GetItemAsync<T, U>(SolvasAm.Common.GrpcApi.V1.GetRequest request, ServerCallContext context, RepoQuery<U> repoQuery = null) where T : Google.Protobuf.IMessage<T> where U : Identity
    {
      var resourceName = ResourceName.Parse<T>(request.Name);
      T result = default;

      using var routerScope = _databaseManager.CreateScope(resourceName.OwnerId);
      try
      {
        var modelField = await _repository.GetByIdAsync<U>(SolvasAmHelper.ParseValue<Guid>(resourceName.Id), context.CancellationToken, repoQuery).ConfigureAwait(false);
        result = new[] { modelField }.MapToProto<T, U>(_mapper, request.Name, true).SingleOrDefault();
        result.SetPropertyValue("Name", ResourceName.Format<T>(resourceName.OwnerId, resourceName.Id, resourceName.Parent));
      }
      catch (ItemNotFoundException)
      {
        RpcExceptionHelper.ThrowWithStatus(StatusCode.NotFound, $"\"{request.Name}\" not found.");
      }
      return result;
    }

    private async Task<ListResult<T>> ListItemsAsync<T, U>(SolvasAm.Common.GrpcApi.V1.ListRequest request, ServerCallContext context, RepoQuery<U> repoQuery = null) where T : class, Google.Protobuf.IMessage<T> where U : Identity
    {
      var permissions = await _oidcResourceAuthorizer.GetUserPermissionsAsync(_credentials.CurrentValue.ClientId, context, _logger).ConfigureAwait(false);
      if (request.MetaOnly.HasValue && request.MetaOnly.Value)
        return new ListResult<T>(Enumerable.Empty<T>().ToList(), 0, permissions);

      var resourceName = ResourceName.Parse<T>(request.Parent, false);
      using var _ = _databaseManager.CreateScope(resourceName.OwnerId);
      int? pageSize = request.PageSize > 0 ? request.PageSize : default(int?);
      var modelItems = await _repository.ListAsync<U>(request.Skip, pageSize, request.OrderBy, request.Filter, context.CancellationToken, repoQuery).ConfigureAwait(false);
      var grpcItems = modelItems.MapToProto<T, U>(_mapper, request.Parent, false).ToList();
      return new ListResult<T>(grpcItems, modelItems.TotalSize, permissions);
    }

    private async Task<T> CreateItemAsync<T, U>(T grpcItem, ResourceName resourceName, Dictionary<string, object> callingValues, ServerCallContext context) where T : Google.Protobuf.IMessage<T> where U : Identity
    {
      grpcItem.SetPropertyValue("Id", string.Empty);
      grpcItem.SetPropertyValue("Lid", 0);
      var validator = _serviceProvider.GetRequiredService<IValidator<U>>();
      var modelItem = await _mapper.MapToModelAndValidate(grpcItem, ApiRequestType.CREATE, validator, callingValues, context.CancellationToken).ConfigureAwait(false);

      var newModelItem = await _repository.CreateItemAsync(modelItem, false, context.CancellationToken).ConfigureAwait(false);

      var newGrpcItem = _mapper.Map<T>(newModelItem);
      newGrpcItem.SetPropertyValue("Name", ResourceName.Format<T>(resourceName.OwnerId, newModelItem.Id.ToString(), resourceName.Parent));
      return newGrpcItem;
    }

    private async Task<T> UpdateItemAsync<T, U>(T grpcItem, ResourceName resourceName, FieldMask updateMask, ServerCallContext context, Dictionary<string, object> callingValues = null, FieldMask.MergeOptions mergeOptions = null) where T : Google.Protobuf.IMessage<T> where U : Identity
    {
      var validator = _serviceProvider.GetRequiredService<IValidator<U>>();
      grpcItem.SetPropertyValue("Id", resourceName.Id);
      try
      {
        byte[] hasBytes = Convert.FromBase64String(grpcItem.GetPropertyValue("Etag")?.ToString());
      }
      catch (Exception)
      {
        RpcExceptionHelper.ThrowWithStatus(StatusCode.FailedPrecondition, "Invalid Etag");
      }

      var updateFuncAsync = SolvasAmHelper.GetUpdateFunction(grpcItem, updateMask, _mapper, validator, callingValues: callingValues, mergeOptions: mergeOptions);

      T updatedGrpcItem = default(T);
      using var _ = _databaseManager.CreateScope(resourceName.OwnerId);
      try
      {
        var updatedModelItem = await _repository.UpdateItemAsync(Guid.Parse(resourceName.Id), updateFuncAsync, false, context.CancellationToken).ConfigureAwait(false);
        updatedGrpcItem = _mapper.Map<T>(updatedModelItem);
        updatedGrpcItem.SetPropertyValue("Name", ResourceName.Format<T>(resourceName.OwnerId, resourceName.Id, resourceName.Parent));
      }
      catch (ItemNotFoundException)
      {
        RpcExceptionHelper.ThrowWithStatus(StatusCode.NotFound, $"\"{resourceName.SuppliedResourceName}\" not found.");
      }
      catch (ConcurrencyException)
      {
        RpcExceptionHelper.ThrowWithStatus(StatusCode.Aborted, "Resource was modified or deleted since last fetched. Please refresh the resource and retry.");
      }

      return updatedGrpcItem;
    }

    private async Task<Empty> DeleteItemAsync<T, U>(SolvasAm.Common.GrpcApi.V1.DeleteRequest request, ServerCallContext context) where T : Google.Protobuf.IMessage<T> where U : Identity
    {
      var resourceName = ResourceName.Parse<T>(request.Name);

      SolvasAmHelper.ValidateConfirmed(1, request.OperationConfirmed, $"Delete item?");

      using var _ = _databaseManager.CreateScope(resourceName.OwnerId);
      try
      {
        var modelItem = await _repository.GetByIdAsync<U>(SolvasAmHelper.ParseValue<Guid>(resourceName.Id), context.CancellationToken).ConfigureAwait(false);
        await _repository.DeleteItemsAsync(new[] { modelItem }, context.CancellationToken).ConfigureAwait(false);
      }
      catch (ItemNotFoundException)
      {
        RpcExceptionHelper.ThrowWithStatus(StatusCode.NotFound, $"\"{request.Name}\" not found.");
      }
      return new Empty();
    }

    private async Task<Empty> BatchDeleteItemsAsync<T, U>(
    SolvasAm.Common.GrpcApi.V1.BatchDeleteRequest request,
    ServerCallContext context)
    where T : Google.Protobuf.IMessage<T>
    where U : Identity
    {
      var resourceName = ResourceName.Parse<T>(request.Parent, false);

      var itemsToDelete = new List<U>();
      var notFoundIds = new List<string>();

      using var _ = _databaseManager.CreateScope(resourceName.OwnerId);

      foreach (var name in request.Names)
      {
        try
        {
          var sourceResourceName = ResourceName.Parse<T>(name);
          var id = SolvasAmHelper.ParseValue<Guid>(sourceResourceName.Id);
          var item = await _repository
              .GetByIdAsync<U>(id, context.CancellationToken)
              .ConfigureAwait(false);

          itemsToDelete.Add(item);
        }
        catch (ItemNotFoundException)
        {
          notFoundIds.Add(name);
        }
      }

      if (notFoundIds.Any())
      {
        string message = $"{string.Join(", ", notFoundIds)} not found.";
        throw new RpcException(new Status(StatusCode.NotFound, message));
      }

      await _repository
          .DeleteItemsAsync(itemsToDelete, context.CancellationToken)
          .ConfigureAwait(false);

      return new Empty();
    }

