    public async override Task<SolvasAm.Common.GrpcApi.V1.ListFieldUsagesResponse> ListFieldUsages(SolvasAm.Common.GrpcApi.V1.ListRequest request, ServerCallContext context)
    {
      var result = new SolvasAm.Common.GrpcApi.V1.ListFieldUsagesResponse();
      var resourceName = ResourceName.Parse<SolvasAm.Common.GrpcApi.V1.FieldUsage>(request.Parent, false);
      var permissions = await _oidcResourceAuthorizer.GetUserPermissionsAsync(_credentials.CurrentValue.ClientId, context, _logger).ConfigureAwait(false);
      result.UserPermissions = _mapper.Map<SolvasAm.Common.GrpcApi.V1.UserPermissions>(permissions);

      // If the meta_only field is not set or is set to false, fetch the data
      if (!request.MetaOnly.HasValue || !request.MetaOnly.Value)
      {
        request.Filter = FilterBuilder<SolvasAm.Common.GrpcApi.V1.FieldUsage>.From(request.Filter).And(f => f.FieldName, ComparisonOperator.EQ, resourceName.Id).Build();

        var modelItems = await _repository.GetFieldUsagesAsync(resourceName.OwnerId, request.Filter, context.CancellationToken).ConfigureAwait(false);
        var grpcItems = modelItems.Select(_mapper.Map< SolvasAm.Common.GrpcApi.V1.FieldUsage>); //can't use MapToProto() here as SolvasAm.Common.Model.FieldUsage doesn't inherit from Identity
        result.FieldUsages.AddRange(grpcItems);
        result.TotalSize = 0; //we don't provide the actual count as the procedure doesn't support paging
      }

      return result;
