    [AuthorizeOwner("datadictionary-fieldusage-list.delete", NameProperty = "Parent")]
    [ValidateRequest(ApiRequestType.CUSTOM, ValidationProperty = "Parent")]
    public async override Task<Empty> DeleteFieldUsage(SolvasAm.Common.GrpcApi.V1.DeleteFieldUsageRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<SolvasAm.Common.GrpcApi.V1.FieldUsage>(request.Parent, false);
      SolvasAmHelper.ValidateConfirmed(1, request.OperationConfirmed, SolvasAmHelper.GenerateDeleteConfirmationMessage(1, "field usage"), "Delete Field Usage");

      try
      {
        string portfolioId = null;
        try
        {
          var portfolio = await GetPortfolioAsync(resourceName, context).ConfigureAwait(false);
          portfolioId = portfolio.Lid.ToString();
        }
        catch (RpcException)
        {
          // since field usages can be requested for a portfolio
          // or outside a portfolio, portfolioId may or may not be present in the parent
          _logger.Info("DeleteFieldUsage api invoked with {ResourceParent}", request.Parent);
        }

        await _repository.DeleteFieldUsageAsync(
          resourceName.OwnerId,
          portfolioId,
