    [AuthorizeOwner("model-list.read")]
    [ValidateRequest(ApiRequestType.GET)]
    public async override Task<ComplianceModelDetail> ExportComplianceModel(ExportJSONDataRequest request, ServerCallContext context)
    {
      var resourceName = ResourceName.Parse<ComplianceModel>(request.Name);
      _logger.Info("ExportComplianceModel api invoked with {resourceName}", request.Name);

      var portfolio = await GetPortfolioAsync(resourceName, context).ConfigureAwait(false);
      try
      {
        var json = await _repository.ExportComplianceModelAsync(resourceName.OwnerId, resourceName.Id, context.CancellationToken).ConfigureAwait(false);
        var root = JObject.Parse(json);
        var models = _mapper.Map<ModelDetail>(root);
        var grpcItems = models.ComplianceModels.FirstOrDefault();

        var applicabilityExpressions = new List<SolvasAm.Common.GrpcApi.V1.ModelExpression>();
        var formulaExpressions = new List<SolvasAm.Common.GrpcApi.V1.ModelExpression>();

        PopulateExpressionsFromModel(grpcItems, applicabilityExpressions, formulaExpressions);
        await Task.WhenAll(
          HydrateModelExpressionsAsync(applicabilityExpressions, resourceName.OwnerId, portfolio.Id.ToString(), DdxPurposeEnum.FILTER_EXPRESSION.ToString(), null, DdxEvaluationTypeEnum.BOOL, context.CancellationToken, HydrateOption.Lite),
          HydrateModelExpressionsAsync(formulaExpressions, resourceName.OwnerId, portfolio.Id.ToString(), DdxPurposeEnum.FIELD_FORMULA.ToString(), null, DdxEvaluationTypeEnum.VALUE, context.CancellationToken, HydrateOption.Lite)
        ).ConfigureAwait(false);
        return grpcItems;
      }
      catch (Exception ex)
      {
        _logger.Error(ex, "Error exporting compliance model {ModelId} for owner {OwnerId}", resourceName.Id, resourceName.OwnerId);
        RpcExceptionHelper.ThrowWithStatus(StatusCode.Internal, ex.Message);
      }
      return default;
    }


