    private void PopulateExpressionsFromModel(ComplianceModelDetail model, List<SolvasAm.Common.GrpcApi.V1.ModelExpression> applicabilityExpressions, List<SolvasAm.Common.GrpcApi.V1.ModelExpression> formulaExpressions)
    {
      if (model.PbRuleGroups != null)
      {
        foreach (var rule in model.PbRuleGroups.Where(g => g.PbRules != null).SelectMany(g => g.PbRules))
          PopulateExpressions(rule.ApplicabilityExpression, rule.FormulaExpression, applicabilityExpressions, formulaExpressions);
      }

      if (model.CalculationGroups != null)
      {
        foreach (var parameter in model.CalculationGroups.Where(g => g.CalculationBlocks != null).SelectMany(g => g.CalculationBlocks).Where(b => b.CalculationBlockParameters != null).SelectMany(b => b.CalculationBlockParameters))
          PopulateExpressions(parameter.ApplicabilityValue, parameter.FormulaValue, applicabilityExpressions, formulaExpressions);
      }

      if (model.PaymentGroups != null)
      {
        foreach (var parameter in model.PaymentGroups.Where(g => g.PaymentGroupSteps != null).SelectMany(g => g.PaymentGroupSteps).Where(s => s.PaymentGroupStepParameters != null).SelectMany(s => s.PaymentGroupStepParameters))
          PopulateExpressions(parameter.ApplicabilityValue, parameter.FormulaValue, applicabilityExpressions, formulaExpressions);
      }

      if (model.Waterfalls != null)
      {
        foreach (var parameter in model.Waterfalls.Where(w => w.WaterfallSteps != null).SelectMany(w => w.WaterfallSteps).Where(s => s.WaterfallStepParameters != null).SelectMany(s => s.WaterfallStepParameters))
          PopulateExpressions(parameter.ApplicabilityValue, parameter.FormulaValue, applicabilityExpressions, formulaExpressions);
      }

      if (model.Tests != null)
      {
        foreach (var parameter in model.Tests.Where(t => t.TestParameters != null).SelectMany(t => t.TestParameters))
          PopulateExpressions(parameter.ApplicabilityValue, parameter.FormulaValue, applicabilityExpressions, formulaExpressions);
      }

      if (model.RecoveryScenarios != null)
      {
        foreach (var rule in model.RecoveryScenarios.Where(s => s.RecoveryRules != null).SelectMany(s => s.RecoveryRules))
          PopulateExpressions(rule.ApplicabilityExpression, null, applicabilityExpressions, formulaExpressions);
      }

      if (model.RatingScenarios != null)
      {
        foreach (var rule in model.RatingScenarios.Where(s => s.RatingRules != null).SelectMany(s => s.RatingRules))
          PopulateExpressions(rule.ApplicabilityExpression, null, applicabilityExpressions, formulaExpressions);
      }

      if (model.EligibilityCriteriaTests != null)
      {
        foreach (var test in model.EligibilityCriteriaTests)
          PopulateExpressions(test.ApplicabilityExpression, test.CriteriaExpression, applicabilityExpressions, applicabilityExpressions);
      }
    }

    private void PopulateExpressions(SolvasAm.Common.GrpcApi.V1.ModelExpression applicabilityExpression, SolvasAm.Common.GrpcApi.V1.ModelExpression formulaExpression, List<SolvasAm.Common.GrpcApi.V1.ModelExpression> applicabilityExpressions, List<SolvasAm.Common.GrpcApi.V1.ModelExpression> formulaExpressions)
    {
      if (applicabilityExpression != null) applicabilityExpressions.Add(applicabilityExpression);
      if (formulaExpression != null) formulaExpressions.Add(formulaExpression);
    }
  }
