using FluentValidation;
using System.Text.RegularExpressions;

namespace SolvasAm.Common.Validators.Expression
{
  public class ModelExpressionValidator : AbstractValidator<Model.Expression.ModelExpression>
  {
    private static readonly Regex _serverTagRegex = new Regex(@"<%[\s\S]*?%>", RegexOptions.Compiled);

    public ModelExpressionValidator()
    {
      RuleFor(r => r.TargetKeyClassic).NotEmpty();
      RuleFor(r => r.TargetType).MaximumLength(4);
      RuleFor(r => r.Ddx).Must(ddx => string.IsNullOrEmpty(ddx) || !_serverTagRegex.IsMatch(ddx))
        .WithMessage("Expression contains invalid server-side tag syntax.");
    }
  }
