using AutoMapper;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using SolvasAm.Common.Caching.Abstractions;
using SolvasAm.Common.Extensions;
using SolvasAm.Common.GrpcApi.ResourceNames;
using SolvasAm.Common.Models;
using SolvasFabric.Grpc.Client;
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

namespace SolvasAmCompliance.Modeling.Shared.CacheDataProvider
{
  public class ServiceBasedSnapshotCacheDataProvider<T> : ISnapshotCacheDataProvider<T> where T : Identity
  {
    protected readonly IServiceProvider ServiceProvider;
    protected readonly ILogger<ServiceBasedSnapshotCacheDataProvider<T>> Logger;
    protected readonly IMapper Mapper;

    public ServiceBasedSnapshotCacheDataProvider(IServiceProvider serviceProvider, ILogger<ServiceBasedSnapshotCacheDataProvider<T>> logger)
    {
      ServiceProvider = serviceProvider;
      Logger = logger;
      Mapper = ServiceProvider.GetRequiredService<IMapper>();
    }

    public async Task<IEnumerable<T>> GetAllAsync(string ownerId, CancellationToken cancellationToken = default)
    {
      IEnumerable<T> result = default;
      Logger.Debug($"Building the snapshot cache using ServiceBasedSnapshotCacheDataProvider for {{{TelemetryConstants.LoggingKeys.Owner}}}, {{EntityType}}", ownerId, typeof(T).Name);

      var modelingClient = await ServiceProvider.GetGrpcClientAsync<GrpcApi.V1.ModelingService.ModelingServiceClient>("compliance-modeling", cancellationToken).ConfigureAwait(false);
      if (typeof(T) == typeof(SolvasAm.Common.Model.Expression.Rule))
      {
        var filter = "hydrate =\"Lite\"";
        string parent = ResourceName.Format<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(ownerId);
        var ruleResponse = await modelingClient.ListModelExpressionRulesAsync(new SolvasAm.Common.GrpcApi.V1.ListRequest { Parent = parent, Filter = filter }, headers: new() { { "caching_request", bool.TrueString }}, cancellationToken: cancellationToken).ConfigureAwait(false);
        result = ruleResponse.ModelExpressionRules.Select(Mapper.Map<T>).ToList();
      }
      return result;
    }

    public async Task<ChangeTracker> GetChangeTrackRecordAsync(string ownerId, CancellationToken cancellationToken = default)
    {
      ChangeTracker result = default;
      GrpcApi.V1.ResourceCollectionStatistics statsResponse = null;
      Logger.Debug($"Fetching the changetracker record using ServiceBasedSnapshotCacheDataProvider for {{{TelemetryConstants.LoggingKeys.Owner}}}, {{EntityType}}", ownerId, typeof(T).Name);
      var modelingClient = await ServiceProvider.GetGrpcClientAsync<GrpcApi.V1.ModelingService.ModelingServiceClient>("compliance-modeling", cancellationToken).ConfigureAwait(false);
      if (typeof(T) == typeof(SolvasAm.Common.Model.Expression.Rule))
      {
        string parent = ResourceName.Format<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(ownerId);
        statsResponse = await modelingClient.GetModelExpressionRulesStatisticsAsync(new GrpcApi.V1.ResourceCollectionStatisticsRequest { Parent = parent }, cancellationToken: cancellationToken).ConfigureAwait(false);
      }

      if (statsResponse != null)
      {
        result = new ChangeTracker
        {
          RecordCount = (int)statsResponse.Count,
          LatestEtag = statsResponse.LatestEtag != null ? Convert.FromBase64String(statsResponse.LatestEtag) : null
        };
      }
      return result;
    }
  }
}

