using AutoMapper;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using SolvasAm.Common.Caching.Abstractions;
using SolvasAm.Common.Extensions;
using SolvasAm.Common.GrpcApi.ResourceNames;
using SolvasAm.Common.Models;
using SolvasFabric.Grpc.Client;
using System;
using System.Collections.Generic;
using System.Diagnostics;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

namespace SolvasAmCompliance.Modeling.Shared.CacheDataProvider
{
  [Obsolete("This class is deprecated. Use ServiceBasedSnapshotCacheDataProvider extension method to instead.")]
  public class ServiceBasedMapDataProvider<T> : IObjectMapChangeTrackingDataProvider<T> where T : Identity
  {
    protected readonly IServiceProvider ServiceProvider;
    protected readonly ILogger<ServiceBasedMapDataProvider<T>> Logger;
    protected readonly IMapper Mapper;

    public ServiceBasedMapDataProvider(IServiceProvider serviceProvider, ILogger<ServiceBasedMapDataProvider<T>> logger)
    {
      ServiceProvider = serviceProvider;
      Logger = logger;
      Mapper = ServiceProvider.GetRequiredService<IMapper>();
    }

    public virtual async Task<IEnumerable<T>> GetAllAsync(string ownerId, string filter, ResourceParent resourceParent, CancellationToken cancellationToken = default)
    {
      IEnumerable<T> result = default;
      Logger.Debug("Building the object map using ServiceBasedMapDataProvider - {owner}, {type}", ownerId, typeof(T).Name);

      Stopwatch stopwatch = new Stopwatch();
      stopwatch.Start();

      var modelingClient = await ServiceProvider.GetGrpcClientAsync<GrpcApi.V1.ModelingService.ModelingServiceClient>("compliance-modeling", cancellationToken).ConfigureAwait(false);
      filter ??= string.Empty;
      if (typeof(T) == typeof(SolvasAm.Common.Model.Expression.Rule))
      {
        filter += "hydrate =\"Lite\"";
        string parent = ResourceName.Format<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(ownerId, parent: resourceParent);
        var ruleResponse = await modelingClient.ListModelExpressionRulesAsync(new SolvasAm.Common.GrpcApi.V1.ListRequest { Parent = parent, Filter = filter }, cancellationToken: cancellationToken).ConfigureAwait(false); ;
        result = ruleResponse.ModelExpressionRules.Select(Mapper.Map<T>).ToList();
      }

      // TODO: Add more types that need to be supported for cache.
      stopwatch.Stop();
      Logger.Debug($"Time to build the map with {result?.Count()} objects is {stopwatch.ElapsedMilliseconds} ms");
      return result;
    }

    public virtual async Task<T> GetByKeyAsync(string ownerId, string key, ResourceParent resourceParent, CancellationToken cancellationToken = default)
    {
      Logger.Debug("Adding an object in the map using ServiceBasedMapDataProvider - {owner}, {type}", ownerId, typeof(T).Name);
      var modelingClient = await ServiceProvider.GetGrpcClientAsync<GrpcApi.V1.ModelingService.ModelingServiceClient>("compliance-modeling", cancellationToken).ConfigureAwait(false);
      if (typeof(T) == typeof(SolvasAm.Common.Model.Expression.Rule))
      {
        string name = ResourceName.Format<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(ownerId, key, resourceParent);
        var rule = await modelingClient.GetModelExpressionRuleAsync(new SolvasAm.Common.GrpcApi.V1.GetRequest { Name = name, }, cancellationToken: cancellationToken).ConfigureAwait(false); ;
        return Mapper.Map<T>(rule);
      }

        // TODO: Add more types that need to be supported for cache.
        return default;
    }

    public async Task<ChangeTracker> GetChangeTrackRecordAsync(string ownerId, ResourceParent resourceParent, CancellationToken cancellationToken = default)
    {
      ChangeTracker result = default;
      GrpcApi.V1.ResourceCollectionStatistics statsResponse = null;
      Logger.Debug("Fetching the changetracker record using ServiceBasedMapDataProvider - {owner}, {type}", ownerId, typeof(T).Name);

      Stopwatch stopwatch = new Stopwatch();
      stopwatch.Start();

      var modelingClient = await ServiceProvider.GetGrpcClientAsync<GrpcApi.V1.ModelingService.ModelingServiceClient>("compliance-modeling", cancellationToken).ConfigureAwait(false);
      if (typeof(T) == typeof(SolvasAm.Common.Model.Expression.Rule))
      {
        string parent = ResourceName.Format<SolvasAm.Common.GrpcApi.V1.ModelExpressionRule>(ownerId, parent: resourceParent);
        statsResponse = await modelingClient.GetModelExpressionRulesStatisticsAsync(new GrpcApi.V1.ResourceCollectionStatisticsRequest { Parent = parent }, cancellationToken: cancellationToken).ConfigureAwait(false);
      }

        // TODO: Add more types that need to be supported for cache.

        if (statsResponse != null)
      {
        result = new ChangeTracker
        {
          RecordCount = (int)statsResponse.Count,
          LatestEtag = statsResponse.LatestEtag != null ? Convert.FromBase64String(statsResponse.LatestEtag) : null
        };
      }

      stopwatch.Stop();
      Logger.Debug($"Time to fetch the change tracker record is {stopwatch.ElapsedMilliseconds} ms");
      return result;
    }
  }
}

