    private async Task PopulateCriteriaExpressionsAsync<T>(string ownerId, IEnumerable<T> expressionItems, CancellationToken cancellationToken) where T : ICriteriaExpressionItem
    {
      var expressionTasksMap = await GetExpressionsAsync(ownerId, expressionItems.Where(x => x.CriteriaExpressionIdClassic != null).Select(r => r.CriteriaExpressionIdClassic).ToList(), cancellationToken).ConfigureAwait(false);

      foreach (var expressionItem in expressionItems.Where(x => x.CriteriaExpressionIdClassic != null))
      {
        if (expressionTasksMap.TryGetValue(expressionItem.CriteriaExpressionIdClassic, out var modelExpression))
        {
          expressionItem.CriteriaExpression = modelExpression;
        }
      }
    }

    private async Task<IDictionary<string, ModelExpression>> GetExpressionsAsync(string ownerId, IEnumerable<string> expressionIdList, CancellationToken cancellationToken)
    {
      var expressionIds = string.Join("|", expressionIdList.Where(idClassic => !string.IsNullOrEmpty(idClassic) && (string.Compare("0", idClassic) != 0)));
      var filter = $"id_list = \"{expressionIds}\"";
      var expressions = await GetExpressionsAsync(ownerId, filter, cancellationToken).ConfigureAwait(false);
      return expressions.ToDictionary(e => e.LidClassic.ToString());
    }

    private async Task<IList<ModelExpression>> GetExpressionsAsync(string ownerId, string filter, CancellationToken cancellationToken)
    {
      var valuePairs = _sprocTranslator.ParseForValuePairs<ModelExpression>(filter);

      var (expressions, _) = await _sprocContext.GetSprocCommand<ModelExpression>(ownerId)
        .WithParameters(
          new SprocParameter("exp_id", valuePairs.GetValueOrDefault("id")?.Item2),
          new SprocParameter("exp_id_list", valuePairs.GetValueOrDefault("id_list")?.Item2)
        )
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);
      // TODO: This one uses sql and the ModelingSprocContext.EXP_DEAL_EXPRESSION_LIST uses exp_sql as column names. Either we have to modify one
      // of these methods here. But better would be to make it consistent in the sproc to return the same name for column?
      return expressions;
    }

    private async Task<ModelExpression> GetExpressionByIdAsync(string ownerId, string expressionId, CancellationToken cancellationToken)
    {
      var filter = IdentityFilter.GetIdFilter(expressionId);
      var expressions = await GetExpressionsAsync(ownerId, filter, cancellationToken).ConfigureAwait(false);

      if (expressions.Count == 0)
      {
        throw new ItemNotFoundException(); //when searching for a specific item, throw error if none found and caller will handle
      }

      return expressions.FirstOrDefault();

    }

    #endregion

    #region ModelExpression.Rule

    public async Task<IList<Rule>> GetModelExpressionRulesAsync(string ownerId, string filter, CancellationToken cancellationToken, bool tryCache = true)
    {
      if (tryCache)
      {
        Func<Rule, bool> predicate = null;
        try
        {
          if (!string.IsNullOrEmpty(filter))
          {
            try
            {
              predicate = _filterTranslator.Parse<Rule>(filter).Compile();
            }
            catch (Exception ex)
            {
              Logger.Info("The filter provided {FilterExpression} could not be compiled into a delegate for cache filtering. Error: {Exception}. Fetching unfiltered...", filter, ex.Message);
            }
          }
          using var _ = _expRuleCache.OwnerScope(ownerId);
          // The count call on the cache is synchronous and will throw if the cache for the ownerId is not initialized or the snapshot cache
          // itself is not built yet for this owner. In that case, we can fall back to the SProc calls.
          var __ = _expRuleCache.Count;
          return [.. (await _expRuleCache.GetByPredicateAsync(predicate, cancellationToken).ConfigureAwait(false))];
        }
        catch (SnapshotCacheException)
        {
          // fall back to SProc if there's a count exception.
        }
      }

      //fallback to the non-cached version if our cache is empty. We do this because we are using a cache from our own service here and the startup process needs to call the non-cached version to fill the cache.
      var valuePairs = _sprocTranslator.ParseForValuePairs<Rule>(filter);

      var (expressions, _) = await _sprocContext.GetSprocCommand<Rule>(ownerId)
        .WithParameters(
          new SprocParameter("rule_id", valuePairs.GetValueOrDefault("id")?.Item2),
          new SprocParameter("exp_rule_code", valuePairs.GetValueOrDefault("code")?.Item2),
          new SprocParameter("exp_id", valuePairs.GetValueOrDefault("expression_id")?.Item2)
        )
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);
      return expressions;
    }

    public async Task<Rule> GetModelExpressionRuleByIdAsync(string ownerId, string ruleId, CancellationToken cancellationToken)
    {
      var filter = IdentityFilter.GetIdFilter(ruleId);
      var rules = await GetModelExpressionRulesAsync(ownerId, filter, cancellationToken, false).ConfigureAwait(false);

      if (rules.Count == 0)
      {
        throw new ItemNotFoundException(); //when searching for a specific item, throw error if none found and caller will handle
      }

      return rules.FirstOrDefault();
    }

    public async Task<Rule> GetModelExpressionRuleByCodeAsync(string ownerId, string ruleCode, CancellationToken cancellationToken)
    {
      var filter = IdentityFilter.GetCodeFilter(ruleCode);
      var rules = await GetModelExpressionRulesAsync(ownerId, filter, cancellationToken).ConfigureAwait(false);

      if (rules.Count == 0)
      {
        throw new ItemNotFoundException(); //when searching for a specific item, throw error if none found and caller will handle
      }

      return rules.FirstOrDefault();

    }

    public async Task<Rule> CreateOrUpdateModelExpressionRuleAsync(string ownerId, Rule rule, int operationConfirmed, CancellationToken cancellationToken)
    {
      var (ruleId, __) = await _sprocContext.PutSprocCommand<Rule>(ownerId)
        .WithParameters(
          new SprocParameter("rule_id", rule.Lid),
          new SprocParameter("exp_rule_code", rule.Code),
          new SprocParameter("rule_name", rule.Name),
          new SprocParameter("rule_description", rule.Ddx),
          new SprocParameter("rule_comments", rule.Comments),
          new SprocParameter("operation_confirmed", operationConfirmed)
        )
        .ExecuteAsync(cancellationToken).ConfigureAwait(false);

      //After creation of the rule that rule should be visible in Templates -> Rules grid
      await RefreshModelExpressionRulesCache(ownerId, cancellationToken).ConfigureAwait(false);

      return await GetModelExpressionRuleByIdAsync(ownerId, ruleId, cancellationToken).ConfigureAwait(false);
    }

    public async Task DeleteModelExpressionRulesAsync(string ownerId, IList<Rule> rules, int operationConfirmed, CancellationToken cancellationToken)
    {
      foreach (var rule in rules)
      {
        var deleteCommand = _sprocContext.DeleteSprocCommand<Rule>(ownerId);
        await deleteCommand.WithParameters(new SprocParameter("rule_id", rule.Lid))
          .ExecuteAsync(cancellationToken).ConfigureAwait(false);
      }
    }

